import{_ as e,o as t,c as o,a2 as a}from"./chunks/framework.BWuWLRhz.js";const n="/images/cryonics/Death-chart-2.png",p="/images/cryonics/ems.png",l="/images/cryonics/ATP3.jpg",s="/images/cryonics/kidney.jpg",i="/images/cryonics/p12.jpg",c="/images/cryonics/P11.jpg",h="/images/cryonics/Three-Segments-1.png",g="/images/cryonics/Three-Segments-Blue.png",m="/images/cryonics/Three-Segments-comparison.png",f="/images/cryonics/Three-Segments-Yellow.png",w="/images/cryonics/Three-Segments-Green-1.png",b="/images/cryonics/Cryonics-big-picture-4.png",u="/images/cryonics/Cryonics-big-picture-2-2.png",y="/images/cryonics/Cryonics-big-picture-Exponential.png",_="/images/cryonics/28395ff72b29fb268c0cfd4a43433490.jpg",k="/images/cryonics/Table.png",d="/images/cryonics/PDF-button.png",A="/images/cryonics/pinit_fg_en_rect_gray_20.png",F=JSON.parse('{"title":"Why Cryonics Makes Sense","description":"","frontmatter":{"title":"Why Cryonics Makes Sense","titleZh":"为什么人体冷冻保存合情合理","date":"2016-03-25T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2016/03/cryonics.html","slug":"cryonics"},"headers":[],"relativePath":"posts/cryonics.md","filePath":"posts/cryonics.md","lastUpdated":1782886257000}'),q={name:"posts/cryonics.md"};function C(S,r,T,v,P,B){return t(),o("div",null,[...r[0]||(r[0]=[a('<h1 id="为什么人体冷冻保存合情合理-·-why-cryonics-makes-sense" tabindex="-1">为什么人体冷冻保存合情合理 · Why Cryonics Makes Sense <a class="header-anchor" href="#为什么人体冷冻保存合情合理-·-why-cryonics-makes-sense" aria-label="Permalink to &quot;为什么人体冷冻保存合情合理 · Why Cryonics Makes Sense&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2016/03/cryonics.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2016/03/cryonics.html</a> · 2016-03-25</p></blockquote><p><em>我们把这篇文章做成了精美的 PDF,方便打印和离线阅读。<a href="https://gum.co/cryonics" target="_blank" rel="noreferrer">点这里购买。</a></em></p><p>你正在飞机上,忽然听到一声巨响,机身开始剧烈晃动。一分钟后,机长在广播里说:</p><p><em>引擎发生爆炸,飞机将在 15 分钟后坠毁。没有生还的可能。不过有一个可能的出路——飞机上碰巧运着一批降落伞,任何想用它逃生的乘客都可以使用。但我必须警告大家——这些降落伞是实验性的,完全没经过测试,不保证能用。我们也完全不知道下方的地形会是什么样。想要降落伞的人请到过道里排队,乘务员会发给你一个,教你怎么用,然后带你到紧急出口跳下去。选择不用的乘客,请留在座位上——一切很快就会结束,你不会感到疼痛。</em></p><h2 id="你会怎么做" tabindex="-1">你会怎么做? <a class="header-anchor" href="#你会怎么做" aria-label="Permalink to &quot;你会怎么做?&quot;">​</a></h2><p>罗伯特·埃廷格 (Robert Ettinger) 小时候是 1930 年代,他读了大量科幻小说,并且理所当然地认为,以世界前进的速度,科学家们必定会在他有生之年的某个时候攻克衰老。他会活着看到那样一个世界:疾病成为过去式,死亡是人们主动选择的、由自己决定时间的事情。<a href="#footnote-1-4836">1</a><a href="#footnote2-1-4836">1</a>← 第一次来 WBW?点开这些。</p><p>但三十年过去了,衰老和非自愿的死亡依然稳稳地存在着,而那时已经成为物理学教授的埃廷格意识到,科学可能来不及在他这辈子解决这些问题,让他享受到成果。于是他开始琢磨怎么钻这个系统的空子。</p><p>如果他死后不被埋葬或火化,而是能以某种方式被冷冻起来——那么等科学家们最终<em>真的</em>攻克了必死性,他们大概也会有工具和技术把他复活,他就能笑到最后。</p><p>1962 年,他把这个想法写成了一本书,叫《<a href="http://www.cryonics.org/images/uploads/misc/Prospect_Book.pdf" target="_blank" rel="noreferrer">永生的前景</a>》(The Prospects of Immortality),人体冷冻运动就此诞生。</p><p>第一个尝试人体冷冻的人是詹姆斯·贝德福 (James Bedford),一位心理学教授,他在 1967 年因癌症去世,享年 73 岁。此时此刻,他正泡在亚利桑那州的一罐液氮里干他的事儿。其他人也慢慢跟上了,今天,已经有超过 300 人正在液氮罐里悠然地待着。</p><p>现在我们先暂停一下。一年前,我对人体冷冻几乎一无所知,我对它的印象大概就像下面这句话:</p><p><em>人体冷冻 (cryonics,或称 cryogenics) 是一个阴森的过程:把有钱的、接受不了死亡这个概念的死人冻起来,寄希望于未来的人能把他们复活;而这个圈子里那些死忠的人体冷冻爱好者,可能还是个类似山达基教的邪教组织。</em></p><p>然后我开始了解它。这都怪你们——低温保存 (cryonics) 是读者写邮件建议我写的潜在未来主题里出现频率最高的话题之一,我线下见过的读者里至少有五个人当面跟我提起过。而当我开始阅读关于低温保存的资料后,我很快发现,我那句斜体假设句里的很多用词都不对。</p><p>那我们就一边解释低温保存到底是什么、怎么运作,一边把那句话拆开来看。先从这部分开始:</p><p><strong>低温保存 (cryonics),或者叫低温学 (cryogenics),是一种病态的过程,把无法接受死亡这个概念的、有钱的死人冻起来,指望未来的人能把他们复活,而且那帮硬核低温保存爱好者的圈子说不定还是个类似山达基教 (Scientology) 的邪教。</strong></p><p>结果发现,这就相当于在说,「<a href="https://www.youtube.com/watch?v=WRqnTODwvEA" target="_blank" rel="noreferrer">翼装飞行 (Wingsuit flying)</a>,或者叫气象学 (meteorology),是一项穿着翼装在空中飞行的运动。」气象学是研究大气中发生的现象的学科,包括风是怎么运作的,而翼装飞行是一种利用风的过程——你要是觉得这俩是一回事,那你就是个怪人。</p><p>同理,低温学 (cryogenics) 是物理学的一个分支,研究极低温的产生及其效应,而低温保存 (cryonics) 则是利用极低温来尝试保存人体的做法。不是一回事。</p><p>接下来,我们要讨论一串三个具有误导性的词:</p><p><strong>低温保存是一种病态的过程,把无法接受死亡这个概念的、有钱的死人冻起来,指望未来的人能把他们复活,<strong>而且那帮硬核低温保存爱好者的圈子说不定还是个类似山达基教的邪教。</strong></strong></p><p>我们会从头讲起,一边讲低温保存是怎么运作的,一边处理这三个词。</p><p>假设你决定要成为一名低温保存者。步骤如下:</p><p><strong>第 1 步)选一家公司</strong></p><p>目前有四家主要的公司提供低温保存服务——亚利桑那州的 <a href="http://www.alcor.org/" target="_blank" rel="noreferrer">Alcor</a>、密歇根州的低温保存研究所 <a href="http://www.cryonics.org/" target="_blank" rel="noreferrer">Cryonics Institute</a> (CI)、加州的美国低温保存协会 <a href="http://www.AmericanCryonics.org/" target="_blank" rel="noreferrer">American Cryonics Society</a> (ACS),以及俄罗斯的 <a href="http://www.kriorus.com/en" target="_blank" rel="noreferrer">KrioRus</a>。KrioRus 是最新的选项,发展很快,但两大巨头还是 Alcor 和 CI(ACS 没有自己的存储设施——他们把人存在 CI 那儿)。</p><p>从我翻阅的资料看,Alcor 似乎稍微更正规、更高大上一点,而 CI(由这场运动的发起人 Robert Ettinger 创立)则更便宜,给人一种夫妻店的感觉。两家都是非营利机构,各自都有大约 150 人在存储中。Alcor 有一千出头的「会员」(也就是未来某天会进入存储的人),CI 大概是这个数字的一半。</p><p><strong>第 2 步)成为会员</strong></p><p>想成为一名人体冷冻者,你需要填一些表格、签一堆文件并做公证,然后为三样东西付钱:每年的会员费、你死后把遗体运到冷冻机构的运输费,以及处理/储存/复活费。</p><p>Alcor 的<a href="http://www.alcor.org/BecomeMember/scheduleA.html" target="_blank" rel="noreferrer">年度会员费</a>大约是 700 美元,他们的运输费和处理/储存/复活费打包在一起——加起来 200,000 美元。Alcor 还给你个选项:扔掉身体,只冷冻大脑(这叫&quot;神经保存&quot;),这样价格能降到 80,000 美元。</p><p>CI 的<a href="http://www.cryonics.org/ci-landing/funding-for-cryostasis/" target="_blank" rel="noreferrer">年度会员费</a>是 120 美元(或者一次性交 1,250 美元买终身会员),处理等费用是 35,000 美元(终身会员 28,000 美元)。比 Alcor 便宜这么多,主要有两个原因:</p><p>第一,不包含运输。如果你住在机构附近,能省一大笔钱。如果不是,你就得通过他们的合作方签一份运输合同,费用是 95,000 美元(终身会员 88,000 美元)。</p><p>第二,Alcor 把那笔巨额费用中的一半以上用来资助他们所谓的<a href="http://www.alcor.org/AboutAlcor/patientcaretrustfund.html" target="_blank" rel="noreferrer">病人护理信托基金</a>。回到 70 年代,那时候人体冷冻公司更多,其中一些破产了,这意味着他们冷冻的人不再被冷冻了——这可不是什么理想的结局。Alcor 的信托是一笔备用资金,用来确保他们的&quot;病人&quot;不会受到公司财务危机之类事情的影响。</p><p><strong>第 3 步)以你新加入的冷冻公司的名义买一份人寿保险</strong></p><p>听起来很可疑,对吧?但其实也有道理。Alcor 和 CI 都是预算相当紧张的小公司,谁都没能力给你搞什么分期付款计划,还指望你的遗产或亲戚将来把钱付清。在病人这一端,除非你是有钱人,不然冷冻费用就是天价,而一份保证支付你全部冷冻费用的人寿保险,能强制你在一辈子里为这笔费用存钱。对年轻人来说,即便是相当大额的人寿保单也挺便宜——用 CI 的话,你每年只需 300 美元就能全部搞定(120 美元年度会费,180 美元人寿保险覆盖主要费用)。哪怕是 Alcor 更贵的套餐,每月成本也不会超过 100 美元。</p><p>这些费用不算白菜价,但整个人寿保险这套操作,至少对年轻人而言,相当有效地把&quot;有钱人&quot;这个词从我们那句黑红交加的开场白里踢出去了。如果它花的钱和有线电视费或抽烟的开销差不多,你就不需要是有钱人才付得起。</p><p><strong>第 4 步)戴上你的手环,继续过你的日子</strong></p><p>冷冻会员会拿到<a href="http://alcor.org/BecomeMember/" target="_blank" rel="noreferrer">一个手环和一条项链</a>,上面刻着说明和联系方式,并被鼓励一直戴着,这样如果你突然挂了,发现你的人就知道要通知公司。</p><p><strong>第 5 步)死</strong></p><p>好了,现在事情开始变得棘手了。我们通常把生与死之间的界限想成一条泾渭分明的分界线,相信在任何一个时刻,一个人要么明确地活着,要么明确地死了。但让我们花一秒钟审视一下这个假设:</p><p>我们先来聊聊,从健康的角度说,一个人被判定为「没救了」到底意味着什么。我们都同意,一个人算不算「没救了」,取决于他们在哪里、在什么时代。1740 年一个得了严重肺炎的三岁小孩大概率没救了,但同样的孩子得了同样的病,放到今天可能完全可以治愈。同样的故事也适用于一个在马拉维偏远村庄病倒的人,和这个人如果在伦敦病倒时截然不同的命运。「没救了」取决于一大堆因素。</p><p>说「死了」也是同一个道理,乍一听相当反直觉。但 Alcor 的 CEO Max More 是这么解释的:「五十年前,如果你走在街上,有人在你面前一头栽倒、停止呼吸,你会检查一下,然后宣布他死了,把遗体处理掉。今天我们不这么干,今天我们做心肺复苏、做各种各样的事情。五十年前我们以为已经死了的人,现在知道其实没死。」<a href="#footnote2-2-4836">2</a></p><p>今天,「死亡」意味着心脏停跳 4-6 分钟,因为大脑在没有氧气的情况下,过了这么久就会发生脑死亡。但 Alcor 在其网站的 <a href="http://www.alcor.org/sciencefaq.htm" target="_blank" rel="noreferrer">Science FAQ</a> 中解释道:「大脑在缺氧几分钟后『死亡』,并不是因为它立刻被摧毁了,而是因为一连串的连锁反应,导致它在温血循环恢复后的几个小时内注定走向毁灭。用冷血而非温血恢复循环、用高压重新打通阻塞的血管、避免过度供氧、用药物阻断细胞凋亡,都可以阻止这种毁灭。」<a href="#footnote2-3-4836">3</a> 网站接着解释道:「有了新的实验性疗法,现在超过 10 分钟的温性心脏骤停也可以在无脑损伤的情况下存活下来。未来的分子修复技术可能会把复苏的边界推到 60 分钟甚至更远,让我们今天关于『死亡何时发生』的信念彻底过时。」</p><p>换句话说,我们所认为的「死了」其实意思是「在当前条件下没救了」。五十年前一个心脏骤停的人并没有死,他们只是注定会死,因为当时的医疗技术救不了他们。放到今天,那个人还不会被认为已经死了,因为他还没到没救的地步。相反,今天的人在心脏骤停 4-6 分钟后会「死」,因为这恰好是当前现代技术还能帮上忙的极限时长。</p><p>冷冻复生论者 (Cryonicists) 认为死亡不是一个单一的<strong>事件</strong>,而是一个<strong>过程</strong>——这个过程始于心脏停止跳动,终结于后来的某个点,那个点叫做「死亡的信息论判据」——我们就叫它「信息死亡」吧——即大脑损坏到无论现在<strong>还是未来</strong>的任何技术都无法将其恢复到原始状态、也无从提取其信息的那一刻。</p><p>这里有个有趣的思考方式:想象一位病人被救护车送到 A 医院,一家典型的现代医院。这位病人在急救员到达前 15 分钟心脏就停止了跳动,他一到医院就被立即宣告死亡。可是,如果 A 医院的医生得知,街对面的 B 医院刚开发出一项颠覆性的新技术,能够在心脏骤停后 <strong>60</strong> 分钟内的任何时刻救活病人且不留下任何长期损伤,那会怎么样?A 医院的人会怎么做?</p><p>当然,他们会火速把病人送过街到 B 医院去救。如果 B 医院真把病人救回来了,那么按定义,这位病人在 A 医院时其实<strong>并没有</strong>真的死,只不过是<strong>被宣告死亡</strong>了而已——因为 A 医院把他视为无一例外<strong>必死无疑</strong>。</p><p>冷冻复生论者提出的观点是:今天在很多被宣告死亡的病例中,病人并没有死,而只是<strong>必死无疑</strong>——而且确实存在一家 B 医院能救他一命——只不过这家医院不在另一个<strong>地方</strong>,而在另一个<strong>时间</strong>。它在未来。</p><p>这就是为什么冷冻复生论者斩钉截铁地宣称:人体冷冻<strong>不是</strong>在处理死人——而是在处理活人,他们只是需要被转移到未来的医院去接受救治。他们相信,在许多情况下,今日的尸体就是明日的病人(所以他们把被冷冻的客户称为「病人」而不是「尸体」或「遗体」),并把自己的工作视为本质上的「延伸急救医学」。<a href="#footnote2-4-4836">4</a></p><p>但这种急救医学有个重要的附加条件。今天的技术还没办法唤醒被冷冻保存的病人,因此法律上不把它视为医疗程序,而是当作一种奇怪的棺材——也就是说,如果你把一个还没被宣告死亡的人冷冻起来,法律上会视为杀人。哪怕这位病人已经病入膏肓、毫无生望,并且坚决不想在被冷冻保存之前进一步恶化,这也不是一个选项——至少在现行法律下不是(有些人正在<a href="http://www.alcor.org/Library/html/donaldson.html" target="_blank" rel="noreferrer">尝试改变</a>这些法律)。这就把冷冻复生论者置于一个进退两难的境地——而恰恰就是在这里,那个不同的死亡定义派上了用场。</p><p>法律并不把死亡看作一个过程。长期以来,美国法律上的死亡被认为发生在心跳和呼吸停止之时。随着现代医疗手段——比如心肺复苏 (CPR) 和除颤器——开始让这些病人能够被复苏,法律不得不<a href="http://www.uniformlaws.org/ActSummary.aspx?title=Determination%20of%20Death%20Act" target="_blank" rel="noreferrer">修改了法律死亡的定义</a>,把它扩展为包括「大脑所有功能的不可逆停止」。<a href="#footnote2-5-4836">5</a> 旧的以「心跳和呼吸」定义的法律死亡,现在被称为「临床死亡 (clinical death)」——一个中间地带,在这个点上大多数情况下有义务尝试复苏,但病人也可以事先签下「不施行心肺复苏术」(Do Not Resuscitate,DNR) 指令(在临终病人中很常见)。<a href="#footnote-2-4836">2</a> 在 DNR 的情况下,医生或护士会宣告一个临床死亡的病人为法律上死亡——即便复苏努力仍可能救回他们。</p><p>这对人体冷冻 (cryonics) 至关重要。人体冷冻技术人员必须等到法律死亡才能开始处理病人,但借助病人的 DNR 指令,他们可以在心脏停跳后立刻开始流程——远在任何脑损伤发生之前。</p><p>所以,这就是留给人体冷冻的窗口:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Death-chart-2.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Death chart"></a></p><p>这就让我们回到之前的清单,现在可以澄清第五步到底是什么意思了:</p><p><strong>第五步)合法地死掉</strong></p><p>你的合法死亡是整个过程中的一个关键节点,所以别搞砸了。你可以用好的方式、糟糕的方式,或者非常糟糕的方式来完成它。</p><p><strong>好的方式:</strong> 某种可以预见的情况,比如癌症这种典型的病榻场景。这样你就能坐上飞机,飞往斯科茨代尔(Alcor 所在地)或密歇根(CI 所在地),入住人体冷冻公司常年合作的某家指定临终关怀机构。这一点很重要,因为人体冷冻在主流医学界内部是高度争议性的,而且往往不被认可、也不被理解。因此,一些医院和临终关怀机构是「对人体冷冻友好」的,另一些则不是(据说不友好的那些会给人体冷冻人员的工作制造麻烦,或者不给他们医院里器官移植专家享有的那些便利)。一旦你进入临终关怀,人体冷冻公司就可以派人 24 小时待命,这样在你法律死亡的一瞬间,他们就能到场开始处理。</p><p>**糟糕的死法:**突然而意想不到的死亡,比如心脏病发作。运气好的话,身边有人可以在你被送往医院的路上联系人体冷冻公司,让他们赶到医院与你会合;运气差的话,你死了几个小时甚至更久才被人发现。这种情况下,人体冷冻公司会尽力而为。进入冷冻保存时你的大脑状态会比理想情况差一些,但话说回来,谁知道未来的技术能做到什么呢?只要你还在「人体冷冻窗口期」内,还处在死亡的<em>过程中</em>,尚未到达信息死亡,就仍然有希望。</p><p>**非常糟糕的死法:**暴力事故或其他导致你大脑严重受损的情况。最糟的情况下,人体冷冻几乎无能为力——比如那位在 9·11 恐怖袭击中丧生的 Alcor 会员。<a href="#footnote2-6-4836">6</a> 另一种糟糕的结局是死于可疑的犯罪情境,导致警方想做尸检(Alcor <a href="http://www.alcor.org/BecomeMember/toprotectyourself.html" target="_blank" rel="noreferrer">建议</a>会员向政府提交一份「以宗教理由拒绝尸检」的表格)。一位已经签约人体冷冻的女性做过一次 <a href="https://www.reddit.com/r/IAmA/comments/knfcx/i_am_signed_up_for_cryonics_at_my_death_ama/" target="_blank" rel="noreferrer">Reddit AMA</a> 问答,当被问及签约如何改变了她的生活时,她回答说:「我注意到的最大变化是我变得更小心了。我开车更慢、更谨慎、更专注,我更留意周围发生的事情。」因为她不想死于那种非常糟糕的死法。</p><p><strong>第 6 步)尽快降温并转移到人体冷冻设施</strong></p><p>在你被合法宣告死亡后,理想情况下,冷冻团队会立即行动。他们做的第一件事有两个方面——把你放入冰水浴中降低体温、减缓代谢(这样心脏骤停带来的损伤发生得更慢),同时让你的心肺重新工作,保持身体处于稳定状态。他们通过一种叫做 <a href="http://assets1.mytrainsite.com/501494/ems.png?r=1280" target="_blank" rel="noreferrer">thumper</a> 的机械心肺复苏器实施 CPS 来做到这一点(和 CPR 类似,但最后的 S 代表 support 支持,而不是 R 代表 resuscitation 复苏,因为他们并不是要把你救活):<a href="#footnote2-7-4836">7</a></p><p><a href="https://www.michiganinstruments.com/trade-in-program" target="_blank" rel="noreferrer"><img src="'+p+'" alt="ems"></a></p><p>然后他们会给你注射多种药物,确保你不会形成血栓或开始腐烂。</p><p>一旦这些控制住了,他们就可以进行更复杂的操作——通过手术接入你大腿的主要血管,然后接上这个家伙:<a href="#footnote2-8-4836">8</a></p><p><a href="http://www.alcor.org/Library/pdfs/atp.pdf" target="_blank" rel="noreferrer"><img src="'+l+'" alt="ATP3"></a></p><p>那是一台心肺机,负责循环和供氧,这样他们就可以停掉粗糙得多的 CPS 了。这台机器除了循环你的血液,还会把你身体里的热量抽出去,把体温降到略高于水的冰点,并用一种能在超低温下维持生命活力的器官保存液替换掉你的部分血液(这和移植外科医生长途运输器官时保持器官活性的做法类似)。</p><p>如果需要把你空运到人体冷冻机构,他们会把你打包在冰里,送上一趟他们希望不是你人生最后一次的航班。</p><p><strong>第 7 步)玻璃化</strong></p><p>大多数听说过人体冷冻的人都以为它意味着被冻起来。其实不是。它意味着被玻璃化。</p><p>玻璃是个怪东西。它不是典型的固体,因为当它从液态冷却时,从来不会结晶成有序结构。但是,正如我发布这篇文章后被一堆评论者吼了才知道的,它其实也不是液体,因为<a href="http://www.cmog.org/article/does-glass-flow" target="_blank" rel="noreferrer">它并不流动</a>。所以它既不是典型固体也不是液体——它是一种「非晶态固体」,有时被比作一个<a href="http://www.cmog.org/article/does-glass-flow" target="_blank" rel="noreferrer">巨型分子</a>。就我们的目的而言,关键在于,<em>和液体一样</em>,玻璃不会结晶——而是随着冷却,分子只是越动越慢,直到停下。</p><p>如果你把一个人<em>冻</em>起来,他体内所有的液态水最终都会到达冰点并结晶成固体。那可不妙——第一,水冰的体积比液态水大约多 9%,所以它会膨胀,严重损伤组织;第二,锋利的冰晶会切开细胞膜和周围组织。</p><p>所以为了避免这种灾难性的液-固相变,人体冷冻技师会做一件挺酷的事——他们从胸部动手术,把主要动脉接到管子上,把身体里所有血液泵出去,换上一种「冷冻保护剂溶液」,也就是医用级别的防冻液。这做了两件重要的事:它替换了身体细胞里 60% 的水,并且降低了剩余液体的冰点。当操作完美时,结果就是身体里不会有任何冻结发生。取而代之的是,在接下来的三个小时里,他们把你的身体一点点冷却下来,直到 -124ºC,这个关键点叫做「玻璃化转变温度」,此时身体里的液体仍然保持无定形状态,但粘度高到没有任何分子能挪动。你正式成了一个非晶态固体,就像玻璃一样——也就是说,你被<em>玻璃化</em>了。</p><p>分子不再运动,你身体里所有的化学活动都停下来了。生物学时间停止了。你被按了暂停键。</p><p>既然我确定你正在心生怀疑,不妨说一下:玻璃化保存生物组织已经不是什么新鲜事了。人类胚胎、精子、皮肤、骨骼以及其他身体部位,我们已经成功地玻璃化并重新解冻过好一阵子了。最近,科学家<a href="http://www.ncbi.nlm.nih.gov/pmc/articles/PMC2781097/" target="_blank" rel="noreferrer">对一颗兔子的肾脏进行了玻璃化处理</a>:<a href="#footnote2-9-4836">9</a></p><p><a href="http://www.alcor.org/cryomyths.html" target="_blank" rel="noreferrer"><img src="'+s+'" alt="kidney"></a></p><p>然后他们把它解冻,重新放回兔子体内。它照样能工作。</p><p>而就在 2016 年 2 月,人体冷冻领域出现了一项突破——科学家首次对兔脑进行了玻璃化处理,并证明解冻后它处于<a href="https://www.rt.com/news/332074-cryonics-rabbit-brain-regenerated/" target="_blank" rel="noreferrer">近乎完美的状态</a>,&quot;细胞膜、突触和细胞内结构都完好无损……〔这是〕第一次可以证明冷冻保存能够保护与学习和记忆相关的一切。&quot;<a href="#footnote2-10-4836">10</a></p><p>一旦你被玻璃化了,还需要继续一点点降温,大约两周后,你的温度会降到 -196ºC。为什么是这个温度?因为这是氮气变成液体的温度,而你即将开始一场长期的液氮浴。</p><p><strong>第 8 步)进入储存</strong></p><p>或者用 Alcor 的委婉说法,叫&quot;长期照护&quot;。玻璃化之后的新版你会被放进一个基本上就是大号立式保温瓶的容器里,大约 10 英尺高,3.5 英尺宽。<a href="#footnote2-11-4836">11</a></p><p><a href="http://www.alcor.org/AtWork/index.html" target="_blank" rel="noreferrer"><img src="'+i+'" alt="p12"></a></p><p>你会认识你的新邻居——另外三个玻璃化的人,每人占据保温瓶的一个象限,再加上五个&quot;轻装出行&quot;的人——他们没有身体,头颅堆叠在中间那一列。<a href="#footnote2-12-4836">12</a></p><p><a href="http://www.alcor.org/AtWork/index.html" target="_blank" rel="noreferrer"><img src="'+c+'" alt="P11"></a></p><p>或者,如果你在只保存头部的保温瓶里,你将和 45 个大脑共用这个空间(真正被保存的是大脑,但他们把大脑留在头里,因为把大脑取出来比留在原位风险更大,所以就把头当成了运输箱)。</p><p>哦,对了,你是倒立着的。这是因为液氮会从容器顶部慢慢蒸发。正常情况下这不是问题——工作人员大约每周补充一次。但如果出现最糟糕的情况,一个容器被迫长时间无人照管,那么头部会是最后一个受影响的部位——病人倒立意味着液氮蒸发到暴露头部,需要六个月的时间。</p><p>至于停电,人体冷冻的病人完全安全——他们的储存过程根本不涉及电力。</p><p>而这就是你要待的地方。也许 10 年。也许 150 年。也许 1200 年。但时间对你来说无所谓。你只是被按下了暂停键。</p><p>现在是我们退一步、看一下全景的好时机了。如果 A 点是「我决定要报名冷冻」,B 点是「哦酷,现在是 2482 年,我在这儿干着各种事」,那么要从 A 走到 B,有四个大大的「如果」必须全部朝正确的方向发展:</p><p><strong>1) 如果我以不算太糟糕的方式合法死亡,并且把我塞进保温瓶的一切都按计划进行</strong></p><p><strong>2) 如果未来的人类真的达到了能把我完全复活到健康状态的技术水平</strong></p><p><strong>3) 如果冷冻公司能一直安全、不间断地保存我直到那一刻</strong></p><p><strong>4) 如果那一刻真的来临时,外面的世界真的会采取行动把我复活</strong></p><p>——那么我就能在 2482 年那儿干着各种事了。</p><p>你目前走的那八步——从选一家冷冻公司开始,到你躺进保温瓶结束——只完成了第一个「如果」,其他所有「如果」仍然横亘在你和冷冻之旅的下一步——复活——之间。</p><p>要理解我们怎么能走到那一步,得先弄清楚这四个「如果」都是怎么回事。</p><p>我们先从「如果」1-3 开始讲,它们必须一起讨论,因为它们相互依赖、协同工作。为了说明原因,我们把它们放到同一张图里:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Three-Segments-1.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Three Segments"></a></p><p>这条线的三个线段对应「如果」1、2、3。但这张图乍看有点误导人,因为虽然三段都躺在同一条线上,它们代表的其实是三个不同的概念:</p><ul><li><strong>蓝色线段</strong>(如果 1)代表你初始保存的质量。</li><li><strong>黄色线段</strong>(如果 2)代表医疗技术随时间前进的能力。</li><li><strong>绿色线段</strong>(如果 3)代表在蓝色和黄色线段最终能相连之前,还需要多少时间来跨越它们之间的空隙。</li></ul><p>思路是这样的:你被保存得越好,蓝色线段就往右伸得越远;随着技术越来越牛,黄色线段就往左朝蓝色线段伸得越来越远。这个过程中绿色线段越来越短,直到最终绿色线段消失、蓝黄两段接上——也就是说医疗技术已经达到了能把你复活的水平。</p><p>冷冻的很多关键细节都围绕这里展开,所以我们来深入聊聊这三段中的每一段:</p><p><strong>蓝色线段——你保存的质量(对应如果 1)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Three-Segments-Blue.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Three Segments Blue"></a></p><p>蓝色段的长度对应的是<em>保存质量</em>。或者说,最简单地讲,你在保温瓶里的玻璃化状态和完全恢复健康的你之间的障碍越少,蓝色段就<em>越长</em>——因为如果把你放进保温瓶之前发生的一切都尽可能顺利,那么它离终点 B 就<em>走得越远</em>,也就意味着黄色段那头要做的复活工作<em>越少</em>。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Three-Segments-comparison.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Three Segments comparison"></a></p><p>决定蓝色段长度的主要因素是:你玻璃化的大脑的原子结构与其在活着、健康时的原始原子结构有多接近。</p><p>请注意我说的是&quot;大脑&quot;,不是&quot;身体&quot;,因为这里我们主要在乎的是大脑。人体冷冻学家和我们许多人一样,相信<em>你之所以是你</em>,归根结底在于你的大脑。如果在未来,你现有的这颗大脑活在一具合成身体之上,而你确切的记忆和人格完好无损,人体冷冻学家们会满意地认为你&quot;活下来了&quot;。这也是为什么有些人连身体都懒得玻璃化。</p><p>第二点要注意的是,科学家相信短期记忆存在于大脑<em>活动</em>中——存在于流经大脑的<em>电流</em>里——而你的长期记忆、人格、知识,以及一切让你成为&quot;你&quot;的东西,都存在于大脑的<em>结构</em>里——也就是构成你大脑的原子的特定排列方式。<a href="#footnote2-13-4836">13</a></p><p>在法律死亡之前你大脑里的任何电活动都会在玻璃化过程中丢失,所以你被复活时不会带有玻璃化前生命末段的短期记忆。但玻璃化<em>能够</em>保存的是你大脑的结构,而方便的是,那正是我们唯一在乎的东西。</p><p>这个概念让我们更清楚地理解人体冷冻学家眼中的死亡。对他们来说,完美的健康意味着你健康大脑中原子的确切排列完好无损,而死亡的过程意味着这种排列由于衰老、伤害、疾病,以及最终心脏停跳所引发的效应等现象而逐渐劣化。对他们来说,死亡意味着:你大脑的原始结构变得<em>如此</em>混乱,以至于连最高端的未来科学实验室都无法搞清原来的排列长什么样——这就是信息死亡 (info death) 的定义。</p><p>把大脑比作电脑硬盘,信息死亡的概念就容易理解了。埃利泽·尤德科夫斯基 (Eliezer Yudkowsky) 解释了要让一块电脑硬盘达到信息死亡实际上有多难:<a href="#footnote2-14-4836">14</a></p><p><em>如果你想彻底抹除一块硬盘,可不是简单地用 0 覆盖一遍就行。当然,这样「抹除」过的硬盘,你再插回电脑肯定是启动不了的。但如果这块硬盘落到一个手握扫描隧道显微镜的专家手里,他能分辨出「这里原本是 0,被 0 覆盖」和「这里原本是 1,被 0 覆盖」的区别。</em></p><p><em>市面上有一些号称能「安全抹除」硬盘的程序,方法是反复用 0、1 和随机数据覆盖多次。但如果你想让硬盘上的秘密扛得住未来可能出现的一切技术,那就浇上铝热剂点火烧掉。这是唯一保险的办法。</em></p><p>他把同样的逻辑套用到人脑上,来论证冷冻保存的病人有朝一日应当是可以复活的:</p><p><em>给一个人灌满冷冻保护剂、逐步降温直到可以放进液氮里保存,这可不是抹除一个人的靠谱方法。</em></p><p>换句话说,可以合理地假设,未来最顶尖的神经科学家将会<strong>极其</strong>擅长从一个受损的玻璃化大脑中读取线索、还原其原本的结构,以至于典型的衰老、疾病、心跳停止再加上玻璃化这套组合拳,大概率难不倒他们。而对冷冻主义者来说,如果未来的科学家能检查你玻璃化后的大脑、弄清楚它本来该是什么样,那么按定义你就没死。</p><p>蓝色段——也就是保存质量——的长度,受三件事影响:</p><p><strong>1)你在法律意义上死亡之前,大脑受损了多少。</strong> 你死时多大年纪?那时你的大脑退化到什么程度了?你有没有患过阿尔茨海默这类导致痴呆的疾病?这病对你的大脑造成了多少永久性损伤?<a href="#footnote-3-4836">3</a> 让你丧命的东西有没有伤到你的大脑(比如脑癌,或头部外伤),还是你的大脑毫发无损?</p><p><strong>2)从你法律死亡到冷冻团队开始处理你之间,受损了多少。</strong> 理想情况是,你的心脏一停,在大脑发生任何变化之前,你就被稳定住并放到冰上。但现实往往不这样,法律死亡后每过去一分钟无人处理,都会对大脑造成大影响,让蓝色段变短。不过冷冻主义者认为,真正的信息死亡其实要在法律死亡之后好几个小时、甚至好几天才发生,即便是「死」了一阵子才被发现的人,冷冻保存也常常还有希望。</p><p><strong>3)玻璃化过程本身造成了多少损伤。</strong> 玻璃化本身——至少按目前的做法——会对大脑造成损伤。冷冻学研究主要就是在想办法减轻这一点,自 1970 年代最早期以来已经有了长足的进步——<a href="http://alcor.org/AboutCryonics/index.html" target="_blank" rel="noreferrer">这个页面</a>底部的一系列图片展示了取得的进展。</p><p><strong>黄色部分——随着时间推进,医疗科技进步的状态(对应 If 2)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Three-Segments-Yellow.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="Three Segments Yellow"></a></p><p>随着医疗科技越来越先进,黄色部分不断变长——但是蓝色部分是向右延伸的,而黄色部分是向<em>左</em>延伸的。关键时刻会在技术终于牛到黄色部分和蓝色部分接上的那一刻发生,那时你就正式变得&quot;可复活&quot;了。</p><p>几个问题:</p><p><strong>If 2 <em>会</em>发生吗?技术<em>究竟</em>会不会有一天先进到能把你复活?</strong></p><p>假设 If 1 拿到了对勾,冷冻主义者相信 If 2 有朝一日也很可能拿到对勾。因为要让 If 2 彻底失败,只有两种方式:</p><ol><li><p>出于某种原因,人类在到达 If 2 关键点之前就永久停止推进医疗科技。</p></li><li><p>人类在到达 If 2 关键点之前就灭绝了。</p></li></ol><p>除了这两种情况以外,If 2 早晚会配合的。理论是,只要<em>未来技术足够</em>先进,总有一天你会变得可复活。</p><p><strong>If 2 会在<em>什么时候</em>发生?我要多久才能被复活?</strong></p><p>这部分取决于冷冻复活的技术挑战究竟有多大、技术推进得有多快——但也取决于 If 1 完成得有多好。刚才说过了,If 1 越顺利,If 2 就越早发生。</p><p><strong>If 2 会<em>怎么</em>发生?哪种未来技术可能复活被玻璃化的人?</strong></p><p>嗯,这取决于我们说的&quot;复活&quot;是什么意思。冷冻主义者似乎有 A 计划和 B 计划。</p><p><strong>A 计划:把玻璃化的患者恢复为健康的人类</strong></p><p>在 A 计划下,复活就是把玻璃化的大脑结构恢复到原本的状态——也就是把所有原子放回它们该在的位置。要做到这一点,你需要两样东西:</p><ol><li><p>原子该放在哪里的信息</p></li><li><p>一种能把原子放到该在位置的方法</p></li></ol><p>如果今天的玻璃化程序做得到位,第一样就有着落了——前提是未来的神经科学家变得非常擅长从检查玻璃化大脑所能收集到的信息中,还原大脑原本的状态。</p><p>第二样需要<em>分子纳米技术 (molecular nanotechnology)</em>。想快速了解纳米技术,我从<a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-2.html" target="_blank" rel="noreferrer">人工智能那篇文章</a>里偷一段蓝框过来:</p><p><strong>纳米技术蓝框</strong></p><p>纳米技术 (Nanotechnology) 是我们对那种处理 1 到 100 纳米尺度物质操控的技术的称呼。一纳米是十亿分之一米,或者说百万分之一毫米,而这 1-100 的范围涵盖了病毒 (直径 100 纳米)、DNA (宽 10 纳米),以及像血红蛋白 (5 纳米) 这样的大分子和葡萄糖 (1 纳米) 这样的中等分子。如果/当我们征服了纳米技术,下一步就是操控单个原子的能力,而原子只小了一个数量级 (约 0.1 纳米)。<a href="#footnote-4-4836">4</a></p><p>为了理解人类试图操控该尺度物质的挑战,让我们把同样的事情放大到更大的尺度上看。国际空间站 (ISS) 位于地球上空 268 英里 (431 公里) 处。如果人类是巨人,大到脑袋能伸到国际空间站那么高,他们大约会比现在的自己大 25 万倍。如果你把 1 纳米到 100 纳米的纳米技术范围放大 25 万倍,得到的是 0.25 毫米到 2.5 厘米。所以纳米技术相当于一个身高等于国际空间站高度的巨人,想办法用一粒沙到一颗眼球之间大小的材料,小心翼翼地建造精密物体。要达到下一个层级——操控单个原子——这个巨人得小心翼翼地摆放 1/40 毫米大小的东西——小到正常人类需要显微镜才能看见。<a href="#footnote-5-4836">5</a></p><p>纳米技术最早由理查德·费曼 (Richard Feynman) 在 1959 年的一次演讲中讨论过,当时他解释道:「在我看来,物理学原理并不排除逐个原子操控物质的可能性。原则上……物理学家有可能合成化学家写下来的任何化学物质。……怎么做?按化学家说的位置把原子放下去,你就造出了那个物质。」就这么简单。如果你能搞清楚怎么把单个分子或原子挪来挪去,你真的可以造出任何东西。先进到允许我们在原子层面进行工程操作的纳米技术,叫做分子纳米技术 (molecular nanotechnology, MNT)。</p><p>人类还没有征服 MNT,科学家们对人类到达那一步需要多久争论不休。但等我们做到那天,我们回头看今天的技术,可能会觉得它极其原始,就像科学家拉尔夫·默克尔 (Ralph Merkle) <a href="http://www.zyvex.com/nano/" target="_blank" rel="noreferrer">描述</a>的那样:「今天的制造方法在分子层面上非常粗糙。铸造、研磨、铣削,甚至光刻,都是在轰隆隆地按统计学的大群方式挪动原子。就像戴着拳击手套试图用乐高积木搭东西。是的,你可以把乐高积木推成一大堆一大堆的,但你没法真的按你想要的方式把它们卡在一起。」</p><p>分子纳米技术 (MNT) 将在多到无法想象的领域里成为颠覆性变革,其中之一就是医学。大脑的突触说白了就是原子的一种特定排列方式,所以如果我们有工具能把原子挪来挪去、放在我们想要的位置,那我们就能完美地「修复」一个受损的突触。人体冷冻学家们相信,MNT 是未来复活并修复冷冻患者的关键。</p><p>有些人一想到复活,第一反应就是:这个人被复活时,难道不还是玻璃化之前那个又老又病快要死的人吗?但计划不是这样的。当我们发展到拥有那种不可思议的技术、能够精准操控原子来复活一个人时,我们也应该同时拥有修复和年轻化他们的技术。对于一个在进入保温瓶之前正因癌症而濒死的人来说,他们能被成功复活,不仅意味着癌症很可能早已被攻克,连衰老大概也一样。</p><p>同样道理,到那时候,我们要么能让病人玻璃化的身体重返年轻,要么干脆造一个全新的、运作完美的身体。Alcor 的医疗响应主任 Aaron Drake 解释说:「我们已经知道能再生一个小器官,能培育出一颗新的心脏。我们知道能用三维打印技术打印细胞和心脏。所以到某个时间点,我们需要再生她的整个身体,或者至少是她的所有器官,再把它们组装起来。然后我们要把那颗大脑移植进这个新身体里。」<a href="#footnote2-15-4836">15</a></p><p><strong>Plan B:把人的大脑信息上传到虚拟世界</strong></p><p>Plan B 和 Plan A 的第一个要求是一样的——那些原子应该放在哪儿的信息——但它不需要物理组装。取而代之的是,Plan B 依赖一种假想中的未来技术,叫做「全脑仿真 (whole brain emulation)」,也就是把一整个大脑结构以完美精度上传到计算机里,让这个人的一切都完好无损地、活生生地存在于一个虚拟世界中。</p><p>听起来超好玩,对吧?</p><p>如果物理复活太难实现,或者复活的时间点太遥远、以至于物理世界都已经彻底过时了,那这就是一个选项。如果人类真能搞出全脑仿真,那你就能被复活到一个神奇的虚拟世界里醒来,完全有意识,不再受生物学和物理世界的种种限制与脆弱所束缚。求求了。</p><p>虽然 Plan A 和 Plan B 都需要跨越巨大的技术障碍,但冷冻学家们强调,这两种方案在理论上都是可能的。</p><p><strong>绿色部分——你需要在储存中安全待多久,才能等到技术能够复活你(这与「如果 3」有关)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Three-Segments-Green-1.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="Three Segments Green"></a></p><p>绿色部分的任务很简单:撑住一切,直到黄色部分接上蓝色部分。</p><p>那么,什么会搞砸「如果 3」呢?什么会破坏一个玻璃化后的人在液氮里安安稳稳浸泡足够长时间的能力?</p><p>有很多事情。比如:</p><p>**人体冷冻公司搞砸了。**人为失误引发的灾难——比如说,保温罐破了个洞让热量进去,液氮在员工反应过来之前全部蒸发掉了。</p><p>**人体冷冻公司破产,而且没有资金、意愿或组织能力去制定一个能拯救病人的方案。**我之前提过,早期的一些公司就发生过几次这样的事。今天的主要公司都声称他们已经建立了牢靠的备用计划以应对最坏情况,这层安全保障正是 Alcor 那笔巨额信托基金的主要用途。</p><p>**自然灾害。**地震、龙卷风或者别的什么东西把装保温罐的建筑砸个稀巴烂。美国两家主要的人体冷冻公司都不在自然灾害高发地区——Alcor 之所以把自己安在亚利桑那州斯科茨代尔,就是因为那里是全美自然灾害风险<a href="http://www.alcor.org/AboutAlcor/scottsdale.html" target="_blank" rel="noreferrer">最低</a>的地方。即便真发生了自然灾害,病人也可能没事——保温罐很坚固,不用电所以不怕停电,而且就算保温罐破了,还有那个头下脚上的设计,病人的头部会是最后一个受影响的部位。</p><p>**针对人体冷冻设施的恐怖袭击。**世界上有很多人——尤其是宗教界的人——痛恨人体冷冻这个概念。</p><p>**战争。**战争一来什么都不好说了。</p><p>**法律不让人体冷冻公司干它的活。**这事最近就差点发生。2004 年,亚利桑那州的立法者试图通过一项法案,要把 Alcor 纳入州殡葬委员会 (State Funeral Board) 的监管之下。这法案要是通过了,很可能就把 Alcor 关门了。这演变成了一场恶战,主要围绕宗教问题,宗教方面强烈反对 Alcor 的业务——但最终 Alcor 赢了。话虽这么说,为了合法经营,Alcor 只能以「用于研究目的的解剖学捐赠」的名义接收遗体,这是宪法赋予的权利——即人可以为人体冷冻保存研究而捐献自己的身体——所保护的一种做法。目前和法律相关的这个变量看起来相当稳定,但如果某个人的绿色时段很长,需要存 800 年才能复活,那谁他妈知道会发生什么呢——到那个时候,现在的斯科茨代尔可能都已经不属于美国了。</p><p>**人体冷冻公司易主,新老板价值观不同,决定放弃这些病人。**或者更恶毒一点,某个憎恨人体冷冻的人给公司老板开出一个无法拒绝的价码,目的就是要关掉它。所有主要的人体冷冻公司都声称他们由充满热情的人体冷冻主义者经营,并且永远会是如此,这种事不可能发生——但话说回来,谁知道呢。</p><p>绿色段越长、需要撑的时间越久,搞砸 If 3 的概率就越高。如果 40 年后就能复活病人,出岔子的空间要比 2500 年后才能复活小得多。</p><p>但这些公司正尽力为长远打算。关于多久之后才能实现复活这个问题,Alcor 表示:「有人认为要几百年后才能复活病人,另一些人则认为技术变革的加速可能会如此迅速地改变我们的世界,几十年就够了。Alcor 正在为任何时长做准备。」<a href="#footnote2-16-4836">16</a></p><p>随着时间推移,玻璃化和复活技术都在改进,蓝色段和黄色段都会向内移动,从两侧蚕食绿色段。大局也许可以这样来描绘:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Cryonics-big-picture-4.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="Cryonics big picture"></a></p><p>这就是蓝、绿、黄三段是如何相互配合运作的。人体冷冻公司常说,人体冷冻会是一件「后进先出」的事,而这张图正好说明了为什么——</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Cryonics-big-picture-2-2.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="Cryonics big picture 2"></a></p><p>在你需要被玻璃化之前经过的时间越长,你受到的玻璃化技术就越先进,<em>而且</em>复活技术也已经推进得更远——这个更小的技术鸿沟意味着更早的复活日期。而要依靠人体冷冻公司照顾你的时间越短,你承担的风险也就越小。</p><p>需要理解的一点是:图中的蓝线适用于<em>普通</em>的人体冷冻患者——一个在晚年患上阿尔茨海默症的人,进入玻璃化时的状态会比同时代的普通人差,所以他面临的挑战会比对应他死亡年份的蓝线高度更严峻。</p><p>当然,图上那些简单笔直的线只是在描绘一个大致概念。实际曲线不会是笔直或可预测的。有一种颇具希望的情况是:技术进步的加速度<a href="#footnote-6-4836">6</a>可能意味着蓝线和黄线会随着时间以越来越快的速度改进,看起来会是这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Cryonics-big-picture-Exponential.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="Cryonics big picture Exponential"></a></p><p>前三个「如果」就是这么回事。听起来都很美好——但如果「如果 4」不成立,前面这些都没意义。没有「如果 4」——也就是「时候到了,真的会有人把我复活吗?」——你依然只是一具无助的、玻璃化的躯体,一旦你变得可以复活,而外界没有履行他们那一半的约定,那你就倒霉了——而且你永远不会知道发生了这一切。</p><p>你会有点像一头农场里的牲畜。你理论上可能有权利,但没有能力捍卫自己的权利,只能依靠别人替你去争取。</p><p>在深入研究这个话题、和人们聊起它的时候,我注意到这个担忧似乎会立刻跳进人们的脑海,成为他们认为人体冷冻不太可能成功的理由。</p><p>他们会问:「地球上要处理的问题已经够多了——你真觉得人们会关心把死人复活这种事吗?」</p><p>冷冻主义者对这个问题是有答案的。</p><p>首先,他们指出,患者并不会漂浮在被世界遗忘的罐子里。相反,作为患者,你很可能拥有 A) 高度关注你、迫切希望看到你复活的后代或朋友,B) 更庞大的冷冻主义者社群,他们对你是否被公正对待的热忱,不亚于 PETA 活动人士对动物公正待遇的热忱,以及 C) 你未来看护者的合同义务——就像今天你可能被一位并不认识你的外科医生做手术,但他依然会出于职业义务尽心照顾你一样。</p><p>其次,他们认为,一旦冷冻患者的复活成为现实,公众对「冷冻患者是什么、她应该得到什么样的对待」的认知会发生剧烈的转变:<a href="#footnote2-17-4836">17</a></p><p><em>早在考虑复活今天这些患者变得可能之前,可逆的休眠术就已经被完善为一种主流医疗技术。从那时起,照护那些无法立即被治愈的人的整个传统,会在文化和法律上被大大强化。等到用最古老、最粗糙的技术保存下来的患者可以被复活的时候,从休眠状态中复苏这件事,已经被做过成千上万次,甚至上百万次。可能时就应予以复活的道德和文化律令,会像今天施行急救和紧急医疗救护的义务一样根本、一样强烈。</em></p><p>如果说今天一位冷冻患者看起来只享有农场牲畜般的权利,冷冻主义者预期,这种观点在未来会显得过时而原始。他们相信,冷冻患者会被看得更像今天的昏迷病人。</p><p>听起来很棒,但当然,我们完全不知道未来会怎么发展,也不知道人体冷冻学这个领域和它那些悬停中的病人会处于什么地位。至少看起来还算说得过去——未来冷冻病人的权利会越来越多,而不是越来越少。如果真是那样,「如果 4」就不算什么大问题。</p><p>而如果四个「如果」都朝你希望的方向发展,你终于可以进入下一步了——真正会让你目瞪口呆的那一步。</p><p><strong>第 9 步)被复活</strong></p><p>这将会是相当刺激的体验。</p><p>首先,不管这事发生在你上次有意识后的 30 年还是 2000 年,对你来说感觉都是一样的——大概有点像打了个短盹。你睡觉的时候,是能感觉到时间流逝的——睡了八小时醒来,你不会觉得刚上床一秒,而是能感觉到过了八小时。但泡在液氮保温瓶里被暂停就不一样了。你不会体验到时间的流逝,所以感觉就像你刚刚才在前一段人生里醒着(唯一让它感觉不完全瞬时的原因,是你会丢失短期记忆)。你八成会晕头转向,得有人来跟你解释:A) 你在未来,B) 冷冻成功了,你不再是那个即将死去的人——你健康、焕然一新,准备好重新开始生活了。</p><p>多么<em>震撼</em>。</p><p>作为一个非常不信天堂的人,我经常想,如果我死后醒来发现自己身处某个愉快的来世,我会有多么<em>惊喜地震惊</em>。我会环顾四周,慢慢意识到发生了什么,然后我会说:「等等……<em>我他妈没搞错吧</em>。」然后我会立刻跑到大门口安顿下来,看着其他无神论者一个个进来,就为了看他们经历同样的震惊。</p><p>我想从冷冻中被复活大概也差不多是这种感觉。可能震撼程度<em>稍微</em>低几档,因为你之所以去冷冻,大概是觉得它有那么一线可能会成功——但仍然是相当大的<em>我他妈没搞错吧</em>时刻。</p><p>初始的震惊之后,你得搞清楚自己醒来的是个什么样的世界。几种可能:</p><p><strong>可能很糟糕</strong>。你可能醒来发现自己身处一个远比你以前生活的世界糟糕得多的未来,而且你在这个世界里一个人都不认识。更糟的是,你可能醒来时处于某种非常可怕的境地——谁知道未来会有什么诡异恶心的事情在发生。</p><p><strong>可能很平淡</strong>。你可能醒来发现世界有点乏味。比如说,它没有你想象中那么未来感十足那么酷,你也不是不朽的,只是被某种程度地恢复了但还是很脆弱,还得找工作,而你在这个时代基本没什么派得上用场的技能。就是那种「随便啦」的感觉。</p><p>**可能会爽到爆。**这大概是最有可能的结局——你醒来之后,可能会觉得爽到不行。那些未来感十足的东西可能酷炫又有趣,超出你的想象。你之前可能 84 岁,浑身酸痛还健忘,然后突然拥有了一副 20 岁完美健壮的身体,或者更棒的东西,比如一具超级合成体,不会感到疼痛或疲惫,也不会生病。你那衰老健忘的大脑可能被修复了,充满了你 50 年来从未体验过的活力。最棒的是,你可能被同样接受了冷冻保存的亲朋好友围绕着,他们<em>超级</em>激动地想见你。这可能爽到爆。</p><p>如果你的玻璃化大脑数据被上传到电脑,然后你在一个虚拟世界里醒来,那可能更疯狂。你不会感觉自己身处电脑里——你会感觉一切都跟你还是人类的时候一样真实,只不过现在一切都很神奇很梦幻,你几乎所有时间都可以用来实现我毕生的梦想:像这只 care bear 一样从彩虹上滑下来。<a href="#footnote2-18-4836">18</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/28395ff72b29fb268c0cfd4a43433490.jpg" target="_blank" rel="noreferrer"><img src="'+_+'" alt="28395ff72b29fb268c0cfd4a43433490"></a></p><p>你的朋友和家人可能也在那里陪着你,同样是虚拟上传的,但依然完完全全是他们自己,保留着所有旧记忆——你们所有人现在都是永恒且不可摧毁的,不再需要物质世界或它的资源。</p><p>谁知道你会在什么样的世界里醒来呢。但有几点让我相信情况应该会相当不错:</p><ul><li>一个真正糟糕的未来世界,大概不会是那种关心保护和复活冷冻患者的世界。在那样的世界里,你可能压根就不会被唤醒。</li><li>同样,一个能复活玻璃化人体的未来,顾名思义技术上已经相当惊人了,所以很难想象你会在一个还没解决我们当今世界各种问题的世界里醒来。</li><li>未来往往比过去更好。人类倾向于预测反乌托邦式的未来,但至少到目前为止,情况恰恰相反。你可以随便吐槽今天世界的种种问题,但当今做人还是比 200 年前、1000 年前或 10000 年前当人要好。</li></ul><p>但因为我们对复活到底会是什么样一无所知,所以还有下一步:</p><p><strong>第 10 步)决定你是否喜欢并想留下</strong></p><p>除非出现某种可笑到不行的场景——比如你被复活到一个永恒虚拟酷刑的世界里,还没办法结束它——这其实说不通——冷冻保存是一场零风险的冒险。它有个撤销按钮——直接自杀就行,就当从没发生过。如果你不喜欢,你的旅程到此为止。否则,进入下一步。</p><p><strong>第 11 步)尽情享受</strong></p><p>我对你的引导差不多就到这里了。你现在只不过是又开始过日子了,和以前一样——但愿是在一个好得多的处境里——从这里开始你做什么真的是你自己的事了。去过你的生活,好好享受身处未来的感觉吧。</p><p><strong>第 12 步) 这次真的死掉</strong></p><h2 id="到了某个时候-你会活够的。没有人会真的想永远活下去-这是我在写graham-数那篇文章结尾时意识到的事实。到了那一天-我猜那个花哨的未来世界会有某种无痛的退场方式——某种能让你信息彻底死亡、数据真正不可恢复的东西。到那时-你就已经过完了自己想过的完整一生-而不是被你恰好出生的那个年代的医疗技术局限硬生生切断的一生。事情本来就该是这样。" tabindex="-1">到了某个时候,你会活够的。没有人会真的想永远活下去,这是我在写<a href="https://waitbutwhy.com/2014/11/1000000-grahams-number.html" target="_blank" rel="noreferrer">Graham 数那篇文章</a>结尾时意识到的事实。到了那一天,我猜那个花哨的未来世界会有某种无痛的退场方式——某种能让你信息彻底死亡、数据真正不可恢复的东西。到那时,你就已经过完了自己想过的完整一生,而不是被你恰好出生的那个年代的医疗技术局限硬生生切断的一生。事情本来就该是这样。 <a class="header-anchor" href="#到了某个时候-你会活够的。没有人会真的想永远活下去-这是我在写graham-数那篇文章结尾时意识到的事实。到了那一天-我猜那个花哨的未来世界会有某种无痛的退场方式——某种能让你信息彻底死亡、数据真正不可恢复的东西。到那时-你就已经过完了自己想过的完整一生-而不是被你恰好出生的那个年代的医疗技术局限硬生生切断的一生。事情本来就该是这样。" aria-label="Permalink to &quot;到了某个时候,你会活够的。没有人会真的想永远活下去,这是我在写[Graham 数那篇文章](https://waitbutwhy.com/2014/11/1000000-grahams-number.html)结尾时意识到的事实。到了那一天,我猜那个花哨的未来世界会有某种无痛的退场方式——某种能让你信息彻底死亡、数据真正不可恢复的东西。到那时,你就已经过完了自己想过的完整一生,而不是被你恰好出生的那个年代的医疗技术局限硬生生切断的一生。事情本来就该是这样。&quot;">​</a></h2><p>既然我们现在对人体冷冻技术 (cryonics) 了解得多多了,让我们把开头那句话拉回来。之前我们停在这里,重点看了标红的那三个词:</p><p><strong>人体冷冻是一种阴森恐怖的做法,把有钱的、死掉的、无法接受死亡这个概念的人冷冻起来,寄希望于未来的人能够把他们复活,而铁杆冷冻圈子说不定还是个类似山达基的邪教。</strong></p><p>我们可以把「有钱的」去掉,因为至少对年轻人来说,一份不那么贵的人寿保险就能付得起冷冻费用。</p><p>我们可以把「死掉的」去掉,因为人体冷冻处理的不是死人,而是那些以他们当下能获得的技术水平来看已注定要死的人。同理,「把他们复活」这个说法也可以换掉。</p><p>我们还可以把「冷冻」去掉,因为人体冷冻并不真的把人冻起来——它是把人玻璃化,变成一种无定形的固态。</p><p>既然到这儿了,顺手也把「阴森恐怖」去掉吧。一个泡在液氮里的玻璃化人头是不是阴森恐怖?是。它比在地下被虫子和微生物啃掉、或者被烧成灰更阴森吗?绝对没有。所以这个词用在这里不公平。</p><p>于是我们得到的句子更接近这样:</p><p><strong>人体冷冻是一种把危重病人暂停下来的做法——这些人无法接受死亡这个概念——寄希望于未来的人能够救他们,而铁杆冷冻圈子说不定还是个类似山达基的邪教。</strong></p><p>然后就是屋子里那头没人愿意提的大象——句子的这部分:<em>……而铁杆冷冻圈子说不定还是个类似山达基的邪教。</em></p><p>我把这句话放进去,是因为当你在打量一个同时具备以下三个特征的东西:A) 一个边缘小众社群,B) 涉及某种可能的永生概念,C) 成员为了一项据说要 1000 年后才能兑现的服务掏出大笔金钱——那你没得选,必须竖起你的「这该不会是山达基那一挂的吧?」天线。</p><p>让那根天线发挥作用的一种方法,就是去读一堆聪明、可信的人写的、认为整件事都是彻头彻尾胡扯的文章。如果说有什么东西能把你从对像人体冷冻这种天马行空的事情的兴奋中泼冷水,那就是专家告诉你为什么这玩意儿该被忽视。</p><p>于是我照做了。在阅读的过程中,我把读到的内容和冷冻学派的反驳做对照,这些反驳我常常能在 Alcor 极其全面的 <a href="http://www.alcor.org/FAQs/" target="_blank" rel="noreferrer">FAQ 页面</a>上找到。其他代表冷冻学派观点的资源包括:人体冷冻研究所 (Cryonics Institute) 前主席 Ben Best 那份详尽的 <a href="http://www.benbest.com/cryonics/CryoFAQ.html" target="_blank" rel="noreferrer">FAQ</a>,Alcor 的<a href="http://www.alcor.org/sciencefaq.htm" target="_blank" rel="noreferrer">科学 FAQ</a>,以及 Alcor 的<a href="http://www.alcor.org/cryomyths.html" target="_blank" rel="noreferrer">迷思页面</a>。</p><p>那些对人体冷冻超级不买账的人,大致可以分成几类:</p><p><strong>怀疑者类型 1:提出正当理由质疑人体冷冻可能行不通的科学家</strong></p><p>主流医学界总体上并不认可人体冷冻。没有医保公司会给它保险,没有政府会补贴它,没有医生会把它当作一种医疗手段来推荐。</p><p>有些怀疑者提出的观点似乎相当有理。生物化学家 Ken Storey <a href="http://www.bbc.co.uk/science/0/23695785" target="_blank" rel="noreferrer">说</a>:&quot;我们有很多不同的器官,而从保存移植器官的研究中我们知道,即便有可能成功地把它们冷冻保存,每个器官也都需要以不同的速度冷却,并使用不同混合比例和浓度的冷冻保护剂。即便你只想保存大脑,大脑也有几十个不同的区域,每个区域都需要采用不同的方案来冷冻保存。&quot;Storey 还指出,要&quot;修复&quot;一个被玻璃化过程损伤的人是多么艰巨的任务,他解释说:&quot;一个人类细胞里大约有 5 万种蛋白质,还有构成膜结构的数亿个脂肪分子。冷冻保存会把它们全都破坏掉。&quot;(Alcor 称这个说法<a href="http://www.alcor.org/notablequotes.html" target="_blank" rel="noreferrer">明显是错的</a>。<a href="#footnote-7-4836">7</a>)</p><p>另一些人则指出,无论是修复一个人类大脑,还是扫描它以便上传,都是极其艰巨的挑战。巴西科学家 Miguel Nicolelis <a href="http://www.smithsonianmag.com/innovation/quest-upload-mind-into-digital-space-180954946/?no-ist" target="_blank" rel="noreferrer">强调</a>,以今天的技术,扫描一个人类大脑的任务需要&quot;一百万台电子显微镜并行运行十年&quot;。研究蛔虫大脑的 Michael Hendricks 认为,让一个人之所以是他自己的那些特质得以复活,这个挑战复杂到根本不可能实现,他<a href="https://www.technologyreview.com/s/541311/the-false-science-of-cryonics/" target="_blank" rel="noreferrer">解释说</a>:&quot;虽然从理论上讲,在死亡组织中保留这些特征或许是可能的,但目前肯定还没做到。做到这一点的技术,更别说从这样一个标本中把这些信息读取出来的能力了,连原理层面都还不存在。&quot;</p><p><strong>人体冷冻派的回应:完全同意</strong></p><p>人体冷冻派其实不怎么反对这些人的说法(Storey 那段引言除外)。他们坦然承认,用今天的技术去复活一个被冷冻保存的人是不可能的。他们只是指出:A) 没有科学证据表明人体冷冻<em>不可能</em>成功;B) 我们不该低估未来技术的能力(想象一下 <a href="http://www.wired.com/2015/07/crispr-dna-editing-2/" target="_blank" rel="noreferrer">CRISPR</a> 对 1700 年的人来说会有多震撼,然后想想对我们来说等价物会是什么);C) 已经出现了一些有希望的进展——比如最近那条 <a href="https://www.rt.com/news/332074-cryonics-rabbit-brain-regenerated/" target="_blank" rel="noreferrer">兔子大脑成功玻璃化保存</a> 的新闻——这说明我们有理由乐观。</p><p>我还从没听哪个人体冷冻派说过「人体冷冻一定会成功」。他们只是觉得,在这件事上,缺乏证据并不等于缺乏可信度。Alcor 的科学 FAQ 就<a href="http://www.alcor.org/sciencefaq.htm" target="_blank" rel="noreferrer">讨论过</a>这一点:「举证责任在于那些提出与既有的成熟科学理论不一致的主张的人。人体冷冻并不与既有的成熟科学理论相矛盾……人体冷冻从不需要以任何方式改变现有的物理定律。」</p><p>人体冷冻派也从不放过任何机会引用下面这些话:</p><p>「登月这种异想天开的念头没有希望,因为逃离地球引力存在无法逾越的障碍。」——Forest Ray Moulton 博士,芝加哥大学天文学家,1932 年。</p><p>「所有关于太空旅行的文章都是彻头彻尾的胡扯。」——Richard Woolley 爵士,英国皇家天文学家,1956 年</p><p>「把一个人放进多级火箭,把他射进月球的引力控制场……我大胆断言:这样的载人航行永远不会发生,无论未来技术如何进步。」——Lee De Forest 博士,著名工程师,1957 年</p><p><strong>怀疑者类型二:科学家,论证人体冷冻不会成功,但他们对人体冷冻的了解还不如刚读完这篇文章的你</strong></p><p>这类冷冻怀疑者数量出乎意料地多。举个例子,主流医学界有惊人多的人会说人体冷冻不可能成功,因为水结冰时会对人体组织造成无法修复的损伤。</p><p><strong>人体冷冻派的回应:同意——所以我们才不冷冻(冻结)人啊。请在开口之前先了解一下什么是人体冷冻。</strong></p><p>在这些字面意义上根本不懂现代人体冷冻是什么的怀疑者里,包括了名人物理学家加来道雄 (Michio Kaku)。我平时挺喜欢他的,但在<a href="https://www.youtube.com/watch?v=m-tcfWnZgCo" target="_blank" rel="noreferrer">这段视频</a>里,他被 Alcor 的 CEO 一顿教育,因为他压根不知道自己在说什么。</p><p>大多数科学家不懂人体冷冻,一部分原因是它的跨学科性质。Alcor 是这么解释的:</p><p><em>任何单一领域的大多数专家都会说,他们不知道有什么证据表明人体冷冻能行得通。这是因为人体冷冻是一个基于<a href="http://www.alcor.org/AboutCryonics/index.html" target="_blank" rel="noreferrer">三个事实</a>的跨学科领域,这三个事实来自不同且互不相关的科学。缺少了其中任何一个,人体冷冻听起来都很荒唐。不幸的是,这就使得有资格评论人体冷冻的专家人数非常少。比如说,极少有科学家知道什么是玻璃化。更少的人知道玻璃化可以保存<a href="http://www.alcor.org/cryomyths.html#myth2" target="_blank" rel="noreferrer">整个器官</a>或<a href="http://www.ncbi.nlm.nih.gov/entrez/query.fcgi?cmd=Retrieve&amp;db=pubmed&amp;dopt=Abstract&amp;list_uids=15247086" target="_blank" rel="noreferrer">整个大脑</a>的细胞结构。尽管玻璃化的这种应用已经发表在文献中,但在人体冷冻领域之外,它太不常见了,以至于只有极少数低温生物学家知道这是可能的。</em></p><p><strong>怀疑者类型 3:低温学 (cryo<em>gen</em>ics) 家,他们不想让其他酷小孩觉得他跟人体冷冻——那个怪怪的圈外人——是朋友。</strong></p><p>低温学家(记住,他们研究的是低温效应的一般科学)和人体冷冻学家之间有一种挺好笑的单方面较劲。低温学家倾向于把人体冷冻当作天文学家看占星术那样看待——或者至少他们出于谨慎在公开场合是这么说的。他们似乎有时会承认人体冷冻背后可能有站得住脚的科学,但他们也知道人体冷冻在更广泛的科学界缺乏可信度,他们不想因为关联被拖进这个声誉问题里(他们对于人们把 cryogenics 和 cryonics 这两个词搞混,也<a href="https://www.cryogenicsociety.org/cryonics/" target="_blank" rel="noreferrer">几乎没什么幽默感</a>)。</p><p><strong>人体冷冻学家的回应:随便啦。</strong></p><p><strong>怀疑者类型 4:相信即使你能复活一个玻璃化的人,那也不是真正的<em>他/她</em>本人。</strong></p><p>这跟我在《<a href="https://waitbutwhy.com/2014/12/what-makes-you-you.html" target="_blank" rel="noreferrer">是什么让你成为你</a>》那篇文章里探讨过的一个哲学难题有关。&quot;你&quot;是你的身体吗?你的大脑?你大脑里的数据?还是什么不那么具象的东西,比如灵魂?当我们思考人体冷冻时,这一切就变得非常重要。你很难在读到人体冷冻复活——尤其是&quot;醒来&quot;发现自己被上传到某个虚拟世界的那种前景——的时候,不问一句:&quot;等等……那还会是<em>我</em>吗?&quot;</p><p>这是对人体冷冻常见的反对意见,但很少有人会有把握地说自己<em>知道</em>这个问题的答案是这样或那样。</p><p><strong>人体冷冻学家的回应:是啊,我们对这点也没底。不过还是祈祷好运吧。</strong></p><p>大多数人体冷冻学 (cryonics) 支持者有一种直觉:<em>你</em>能完好无损地熬过冷冻保存(冷冻学家 Eliezer Yudkowsky 认为「成功的人体冷冻保存能保住你身上一切能通过晚上睡觉、第二天早上醒来而保住的东西」),但他们也承认这又是一个他们并没有把握的变量。你甚至可以把这个当作要加进我们清单里的第五个「如果」:如果那个看起来是复活了的我,<em>真的</em>是我……</p><p><strong>怀疑者第 5 类:不管冷冻学能不能成,反正觉得这是件坏事的人</strong></p><p>这类人可不少。举几个例子:</p><p>**观点:**冷冻学恶心。</p><p>**冷冻学家的典型回应:**没错,但没在地下腐烂那么恶心。</p><p>**观点:**冷冻学诡异,不自然。</p><p>**冷冻学家的典型回应:**当初第一批器官移植手术,人们也是这么说的。</p><p>**观点:**冷冻学是在扮演上帝、逃避死亡。</p><p>**冷冻学家的典型回应:**那把心跳停止的人抢救回来算不算扮演上帝、逃避死亡?化疗呢?</p><p>**观点:**冷冻学是骗局。</p><p>**冷冻学家的典型回应:**几家主要的冷冻学公司都是非营利机构,员工工资很一般,负责公司运营的董事会成员(他们自己也全都签了冷冻协议)则完全不拿报酬。那这个骗局到底是谁在获利?</p><p><strong>观点:</strong>「如果你有足够的钱[做冷冻],你就有足够的钱去帮助今天有需要的人。」——生物伦理学家 Kenneth Goodman<a href="#footnote2-19-4836">19</a></p><p><strong>冷冻学家的真实回应:</strong>「如果你有足够的钱买健康保险(比冷冻贵得多),你就有足够的钱去帮助别人。事实上,如果你有足够的钱花在任何非必需支出上(旅行、体育、看电影、喝啤酒),你都有足够的钱去帮助今天有需要的人。人们一辈子会在无数事情上花大钱,单单把冷冻这项医疗选择挑出来说它自私,完全是任意为之。」<a href="#footnote2-20-4836">20</a></p><p><strong>观点:</strong>「花钱把人的生命保存在深冷环境里是浪费钱,涉及的金额之大,足以充当一种惩罚性作用——对轻信和虚荣自罚一笔罚款。」——生物学家 Jean Medawar<a href="#footnote2-21-4836">21</a></p><p><strong>冷冻学家的真实回应:</strong>「没人会想到把第一批接受骨髓移植或人工心脏的患者叫作『轻信又虚荣』。那被冷冻保存的垂死孩子又算什么?冷冻学是一项实验,选择参与这项实验的人,和其他参与高风险医疗尝试的人一样,应当得到同等的尊重。」<a href="#footnote2-22-4836">22</a></p><p>**观点:**冷冻学会造成人口过剩的灾难。</p><p>**真实的人体冷冻支持者的回应:**这是我在讨论中经常听到的一个问题。Alcor 是这么说的:「那抗生素、疫苗接种、他汀类药物以及它们带来的人口压力呢?单单把人体冷冻这么小、这么投机的东西挑出来当作人口问题来说,是很可笑的。无论有没有人体冷冻,发达地区的人均寿命都会像过去一个世纪那样继续增加。从历史上看,当社会变得更富裕、更长寿时,人口自己会调节。夫妇在更晚的年龄生更少的孩子。这正是现在世界上正在发生的事。最严重的人口问题在于人们贫穷、寿命短的地方,而不是寿命长的地方。」<a href="#footnote2-23-4836">23</a></p><p>**论点:**但泰德·威廉姆斯 (Ted Williams) 啊。</p><p>我来解释一下。有一小撮名人签约了人体冷冻,比如雷·库兹韦尔 (Ray Kurzweil)、纳米技术先驱埃里克·德雷克斯勒 (Eric Drexler),以及像拉里·金 (Larry King)、布兰妮·斯皮尔斯 (Britney Spears)、西蒙·考威尔 (Simon Cowell)、帕丽斯·希尔顿 (Paris Hilton) 这样的名人。<a href="#footnote2-24-4836">24</a> 但在已经玻璃化的大约 300 人里,大牌不多。其中一位是棒球传奇泰德·威廉姆斯。</p><p>一说到人体冷冻,很多人第一个想到的就是威廉姆斯——这是一个人体冷冻支持者恨不得能消失的不幸事实,因为他的故事<a href="http://www.cbsnews.com/news/ted-williams-frozen-in-two-pieces/" target="_blank" rel="noreferrer">深陷丑闻</a>(威廉姆斯的两个孩子说人体冷冻是他自己想要的,而另一个孩子却声称他其实想火化,那个儿子只是为了以后能靠他的 DNA 样本获利才把他冷冻起来)。这段丑陋的故事,不管公平不公平,最终在很多人心里成了人体冷冻行业的一块污点,部分原因是在事件发酵期间,《体育画报》(Sports Illustrated) 发表了一篇<a href="http://www.si.com/vault/2003/08/18/348299/what-really-happened-to-ted-williams-a-year-after-the-jarring-news-that-the-splendid-splinter-was-being-frozen-in-a-cryonics-lab-new-details-including-a-decapitation-suggest-that-one-of-americas-greatest-heroes-may-never-rest-in" target="_blank" rel="noreferrer">文章</a>,报道了这起丑闻,里面有<a href="https://en.wikipedia.org/wiki/Larry_Johnson_(author)" target="_blank" rel="noreferrer">一位 Alcor 前员工</a>的话,指控 Alcor 在威廉姆斯的玻璃化过程中管理失当等等。</p><p>**典型的人体冷冻支持者的回应:**不公平。这块污点是不公平的。那些指控并不属实,那位员工最近还<a href="http://www.alcor.org/press/response.html" target="_blank" rel="noreferrer">在法庭上承认</a>他说的话可能不是真的。</p><p>**论点:**人生已经够长了。人本来就不该活得比现在更久。享受你所拥有的就好。</p><p>**典型的人体冷冻支持者的回应:**谢谢你的意见。我不同意。</p><p>那么在读了大约 50 条怀疑论者的意见之后,我的山达基教 (Scientology) 天线感觉如何?</p><p>嗯,怀疑论者确实让我意识到了人体冷冻眼下面临的挑战有多大。在人体冷冻真正能作为「暂停键」而不是「停止键」发挥作用之前,科学还有很长的路要走——而且我们可能永远走不到那一步。</p><p>但它同样让我坚信,人体冷冻是一件值得追求的事,而且有可能彻底改变游戏规则。冷冻复活看起来是有可能实现的——再加上纵观历史大部分时间里,当时的人根本无法想象未来科技将会把哪些魔法变成现实——这些让我觉得,更稳妥的赌注反而是押在人体冷冻最终<strong>会奏效</strong>上。如果一件重要的事并非<strong>不可能</strong>,那么只要给未来足够的时间,它多半会想出办法让这件事发生。</p><p>冷冻支持者还有一个「为啥不试试?」的论点,怀疑者很难反驳。</p><p>支持冷冻的科学家拉尔夫·默克尔 (Ralph Merkle) 说得很好:<a href="#footnote2-25-4836">25</a></p><p><em>对于「人体冷冻有效吗?」这个问题,科学上正确的回答是:「临床试验正在进行中。一个世纪后再来,我们会根据结果给你答案。」而对于我们这些活不到那时候的人来说,更相关的问题是:「我更愿意当对照组,还是实验组?」我们被环境所迫,必须在不知道临床试验结果的情况下回答这个问题。</em></p><p>要驳倒「我们不知道,但不妨一试」这种回应,唯一的办法就是说:「<strong>绝对</strong>没必要试,因为这<strong>不可能</strong>。」而对于像大脑运作机制和遥远未来的可能性这种深奥莫测的东西,几乎没有几个可信的科学家敢作出如此断言。</p><p>我在了解人体冷冻时还有一个感受:冷冻人士谈起这件事时通常一点都不「推销范儿」。我调研下来的印象是,冷冻圈子里的人往往受过良好教育、理性、务实,并且对自己知道什么、不知道什么都很谦逊。他们坦率承认这个领域的<a href="http://www.alcor.org/problems.html" target="_blank" rel="noreferrer">问题和不足</a><a href="#footnote-8-4836">8</a>,并且小心翼翼地使用有分寸、负责任的措辞,以免扭曲事实中的细微之处。<a href="#footnote-9-4836">9</a> 尽管主流医学界普遍缺乏支持,<a href="http://www.evidencebasedcryonics.org/scientists-open-letter-on-cryonics/" target="_blank" rel="noreferrer">许多有声誉的科学家</a>还是成了冷冻的坚定支持者。</p><p>所以,眼下人体冷冻已经通过了我的「山达基教警报器」检测。</p><p>于是我们那句话可以缩短成这样:</p><p><strong>人体冷冻是一种把处于危急状态、又无法接受死亡这个概念的人暂停下来的过程,期望未来的人能够拯救他们。</strong></p><p>这句话里我接下来想挑战的部分是:</p><p><strong>人体冷冻是一种把处于危急状态、又无法接受死亡这个概念的人暂停下来的过程,期望未来的人能够拯救他们。</strong></p><p>这就是句子中带着一丝翻白眼式轻蔑的部分——人们一听到某人渴望征服死亡时,常常会有这种感觉。除了对人体漂浮在冰冷罐子里这一前景的反感外,我们许多人对人体冷冻 (cryonics) <em>背后的动机</em>也心存厌恶。想要超过标准的一辈子,这似乎太<em>贪婪</em>了。</p><p>我通常不是一个会对这种事情产生轻蔑感的人,但在我研究的早期,当我读到亿万富翁彼得·蒂尔 (Peter Thiel) 前一阵子报名做人体冷冻时,连我自己都忍不住摇了摇头。</p><p>但这篇文章迫使我退后一大步——退到一个能把死亡看作一个过程而非一个瞬间的距离,退到一个能把人类寿命看作我们所处时代的产物而非我们生物学的产物的距离,退到一个能把人类健康的概念铺展在时间长河中的距离,退到一个能想象未来的人类将如何看待我们当下在生物衰败面前束手无策的时代的距离。</p><p>从这个距离往回看,你会突然意识到,我们正处于一个阶段之中——一扇小小的、悲哀的窗口,任何智慧物种都必然会经过它:那时他们已经先进到能够理解自己的必死性,却又原始到无法把自己从中拯救出来。我们应对这一现实的方式,是把死亡当作一个暴君般的霸主,连在自己私下的念头里都不敢挑战它。自我们存在以来,我们就一直被这位霸主全面击败、彻底统治,而我们所知道的一切,就是完全屈从于它的力量,向它俯首称臣。<a href="#footnote-10-4836">10</a></p><p>未来的人类,某天推翻了这位霸主之后,回望我们所处的这个阶段以及由此形成的心理状态,会看得无比清晰——他们会为我们感到悲哀,就像我们为古代邪教中那些被洗脑的信徒感到悲哀一样,那些信徒仅仅因为教主发话就集体自杀。</p><p>在<em>抵抗</em>这位霸主这件事上,我们的意志并没有被打垮——所以我们才会觉得跟癌症斗争到最后一分钟是光荣的,为正义事业冒生命危险还能活着回来是英勇的,而过早向霸主投降选择自杀则是一个可怕的错误。</p><p>但在<em>击败</em>这位霸主这件事上,我们的意志已经被历史彻底压垮了,这段历史告诉我们:霸主是不可摧毁的。</p><p>而这就解释了人体冷冻主义者对人体冷冻的看法,与我们其他人对它的看法之间的鸿沟。这道鸿沟有两个原因:</p><p><strong>1)</strong> 人体冷冻主义者把死亡视为一个<em>过程</em>,他们认为今天被宣告死亡的很多人其实还活着——他们把人体冷冻看作是把一个活着的病人转运到未来某个能救他命的医院去。换句话说,他们把人体冷冻仅仅视为对那位霸主的一种<em>抵抗</em>,和我们看待一个病人被转到另一个地方、那里的医院对他的病有更好的治疗方案没什么两样。而我们大多数人则把死亡视为一个<em>单一的瞬间</em>,所以我们把人体冷冻看作是想把一个死人<em>复活</em>的尝试——也就是说,我们把人体冷冻视为想要<em>击败</em>那位霸主的行为。当冷冻主义者看到我们为一个和癌症抗争的亿万富翁欢呼、却对一个签下人体冷冻协议的亿万富翁摇头,当他们看到我们为一个昏迷的人祷告、却对一个被玻璃化保存的人翻白眼——他们眼里的我们极其不理性。</p><p><strong>2)</strong> 冷冻主义者不把死亡视为一位全能的霸主,而视其为一道有待求解的谜题。他们把人看作是原子的一种排列组合,并且认为只要科学家在处理原子这件事上做得更好一点,这种排列没什么理由必然要走向衰败。所以对他们来说,尝试彻底击败死亡是一件显而易见、理性至极的事业。可我们大多数人却把死亡视为宇宙的一个基本事实——一片神秘又恐怖的阴影,笼罩着所有生灵,只有天真的傻子才会妄图逃脱——所以我们非但不为那些试图破解死亡之谜的人喝彩,反而嗤之以鼻、加以嘲笑,好像他们幼稚得连&quot;接受不可避免的事&quot;都做不到。</p><p>用一个拉远了的镜头去看这件事,对我来说是个巨大的<a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">顿悟时刻 (Whoa Moment)</a>。突然之间,我把这世界上的冷冻主义者们,看得和那些少数试图搞清楚地震机制、以便更好地应对下一次地震的古人是一样的了。我意识到,当我对彼得·蒂尔 (Peter Thiel) 摇头的时候,我就像是那成群结队膜拜诸神、认为是诸神降下了地震来惩罚我们、并想把那些少数科学家绑在柱子上烧死、因为他们的思想是亵渎的——古人中的一员。</p><p>我一开始写这篇文章,只想简单地写一篇关于人体冷冻这个小社群、以及他们在做什么的&quot;迷你博文&quot;,结果写到最后,我又一次盯着一个例子发呆:今天那些自诩崇尚科学、崇尚理性的人,恰是明天的偶像崇拜者。</p><p>我对临终道德的看法也整个翻转了过来。研究刚开始时,我的问题是:&quot;人体冷冻是件可以做的事吗?&quot;到最后,问题变成了:&quot;<em>不</em>给一个濒死的孩子签下人体冷冻协议,这样做真的没问题吗?未来的人们看待这件事,会不会就像我们今天看待那些出于宗教原因拒绝让孩子接受救命医疗的父母一样?&quot;</p><p>人体冷冻很快就变得不只是一件值得一试的好事,而更像是<em>一件正确该做的事</em>。</p><p>阿尔科 (Alcor) 显然就是这么看的。他们说:</p><p><em>人体冷冻的道德论据是:当一个失去意识的人仍有救回来的可能时,中止对他的照护是错误的。这正是为什么昏迷的人会被救护车送去医院,为什么必要时会在重症监护室维持数周,以及为什么就算在那之后没有完全醒来,他们也依然会被照护。只要还有合理的康复希望,照护失去意识的人就是一种道德义务。</em></p><p>而一旦你透过这个视角去看,我们视为正常的一切就都开始显得疯狂了。</p><p>当 <a href="http://www.nytimes.com/2015/09/13/us/cancer-immortality-cryogenics.html?_r=0" target="_blank" rel="noreferrer">Kim Suozzi</a> 在 23 岁得知自己身患癌症将不久于人世时,她报名做了人体冷冻。她把这看作是尝试一种实验性新药——在别的都救不了她的时候,这也许能有一线生机——想都不用想。但她的父亲激烈反对这个决定,<a href="#footnote-11-4836">11</a> Reddit 用户为此嘲讽她,而这件事离奇到足以让《纽约时报》专门写了一篇 <a href="http://www.nytimes.com/2015/09/13/us/cancer-immortality-cryogenics.html" target="_blank" rel="noreferrer">特稿</a>。</p><p>这就好像 Kim 和世上一群身患癌症的 23 岁年轻人一起走向悬崖,准备跌进霸主的血盆大口,而 Kim 看到峡谷对面更高的一处崖壁上垂下一根绳子,于是决定纵身一跃去抓它,因为也许、只是也许,它能把她拉到安全的地方。而《纽约时报》觉得这事儿离谱到、出格到值得写一篇报道。啥?</p><h2 id="从远处看-这就好比我们全都坐在一架正在坠落的飞机上-唯一的求生机会是赌一把这个实验性降落伞——而我们所有人都乖乖坐在座位上不动。" tabindex="-1">从远处看,这就好比我们全都坐在一架正在坠落的飞机上,唯一的求生机会是赌一把这个实验性降落伞——而我们所有人都乖乖坐在座位上不动。 <a class="header-anchor" href="#从远处看-这就好比我们全都坐在一架正在坠落的飞机上-唯一的求生机会是赌一把这个实验性降落伞——而我们所有人都乖乖坐在座位上不动。" aria-label="Permalink to &quot;从远处看,这就好比我们全都坐在一架正在坠落的飞机上,唯一的求生机会是赌一把这个实验性降落伞——而我们所有人都乖乖坐在座位上不动。&quot;">​</a></h2><p>我决定拿起降落伞跳下去。我已经约好 4 月初和一位人寿保险代理人兼阿尔科会员见面,把这套方案办下来。我可以把这个决定归结为三个理由:</p><p><strong>1) 我热爱生活。</strong> 读者们已经注意到我对死亡有一种轻度的执念,这可能和我在这个博客上聊过 55 次死亡有点关系。但他们跟我提起时,都把它称作我对死亡的恐惧。这不太符合我的感觉。更准确地说,我是真的很喜欢活着。我喜欢做各种事,喜欢想各种事,我喜欢我的家人和朋友,如果可以的话我想继续和他们一起玩。我还真的很想看看接下来会发生什么。我想在我们搞明白 <a href="https://waitbutwhy.com/2014/05/fermi-paradox.html" target="_blank" rel="noreferrer">费米悖论 (Fermi Paradox)</a> 时在场,在我们发现暗物质到底是什么时在场,在我们改造火星时在场,在 AI 抢走我们所有工作然后把我们全部灭绝时在场。我想看看 23 世纪是什么样,看看那时的手机能酷成啥样。活着比死了有意思得多。而且既然我拥有整个永恒可以用来死,那么在有机会的时候至少多不死一阵子,似乎是很合逻辑的。</p><p><strong>2) 这张图。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/03/Table.png" target="_blank" rel="noreferrer"><img src="'+k+`" alt="Table"></a></p><p><strong>3) 希望。</strong> 我一直很嫉妒信教的人,因为他们在临终床上想的不是「操」,而是「好啦大时刻到了——我是不是眨个眼就要在天堂醒来了??」有趣多了。也刺激多了。不管人体冷冻 (cryonics) 到底成不成,随着我变老,至少我心里有那么一小部分现在可以想着:「不知道我死后会发生什么呢?」无神论者本来是没资格这么想的。人类要感到充满希望其实并不需要多少希望——他们只需要一样东西可以抓住。只要够让人产生那种「所以你是说还有机会咯!」的感觉就行。</p><p>你们中有些人会认同我的决定——另一些人会觉得这让我显得傻、好骗,或者自私。</p><p>不管怎样,你都应该好好想想这件事,并且意识到——不管你自己是否意识到——你现在其实已经有一个方案了。而那个方案,大概率就是:向死亡投降。走下悬崖,而不是往救生索上跳。飞机往下坠的时候,乖乖坐在座位上。</p><p>这不见得就是错的决定,取决于你是谁、你信什么、你看重什么。但如果那是你的方案,应该是因为你比起另一个选项更喜欢这个方案——而不是因为你压根没想过,只是随大流照着别人做而已。这事关你唯一的一次存在,你必须把这场存在的命运握在自己独立思考的手里。</p><p>而如果你判断下来,你其实更愿意抓个降落伞,而不是留在座位上,那就别掉进一个常见的坑里:</p><p>拖延冷冻症 (Cryocrastination)。</p><p>这在人体冷冻圈里是个真实的术语,用来描述这种现象:人们——尤其是年轻人——嘴上说「废话我死的时候当然要做人体冷冻啊」,然后就再也没真的去走完签约、开始付钱的流程。这也很正常——还有什么事比这更适合拖延的?你清单上那一项——「报名冷冻」——就是死活爬不到待办事项的<em>最上面</em>。但不管你多大岁数,意外都可能发生,而如果那时候你还没来得及签,那你就没戏了。你要是往后退一大步看,在这件事上拖延真的是<em>极其</em>短视。就照我这么做——直接约好预约,这样你就真的会去办了。</p><p>我希望你去做这件事,就像我希望——如果你病了,而这是你唯一的一次机会——你会去试一试那个实验性药物一样。因为值得一试。因为它说不定真的有用。因为凭什么不试呢。也因为狄兰·托马斯 (Dylan Thomas) 说得最好:</p><h2 id="不要温和地走进那个良夜。怒斥-怒斥光明的消逝。" tabindex="-1"><em>不要温和地走进那个良夜。<br> 怒斥,怒斥光明的消逝。</em> <a class="header-anchor" href="#不要温和地走进那个良夜。怒斥-怒斥光明的消逝。" aria-label="Permalink to &quot;*不要温和地走进那个良夜。  
怒斥,怒斥光明的消逝。*&quot;">​</a></h2><p><strong>如果你想了解更多——</strong><a href="http://www.alcor.org/FAQs/" target="_blank" rel="noreferrer">Alcor FAQ</a> 和 <a href="http://www.benbest.com/cryonics/CryoFAQ.html" target="_blank" rel="noreferrer">Ben Best 的 FAQ</a> 是很好的入门资料。<a href="http://www.alcor.org" target="_blank" rel="noreferrer">Alcor</a> 和<a href="http://www.cryonics.org" target="_blank" rel="noreferrer">人体冷冻研究所 (Cryonics Institute)</a> 的网站上信息量都很大,如果你想再深入一层,可以钻进 Alcor 的<a href="http://www.alcor.org/Library/index.html" target="_blank" rel="noreferrer">图书馆</a>(在那里你还能找到<a href="http://www.alcor.org/Library/index.html#casereports" target="_blank" rel="noreferrer">冷冻保存案例报告</a>),或者这一批人体冷冻相关的<a href="http://www.ncbi.nlm.nih.gov/pubmed?orig_db=PubMed&amp;cmd=Search&amp;defaultField=Title%20Word&amp;term=cryonics" target="_blank" rel="noreferrer">期刊文章</a>。下面还列出了更多资料来源。</p><h2 id="如果你想帮忙或参与进来——-你可以捐款给-alcor-或-ci-或者志愿去-alcor-帮忙。alcor-在这个页面的底部列出了一些他们特别需要哪类人来帮忙。" tabindex="-1">**如果你想帮忙或参与进来——**你可以捐款给 <a href="http://www.alcor.org/donate/donate.html" target="_blank" rel="noreferrer">Alcor</a> 或 <a href="http://www.cryonics.org/donate/" target="_blank" rel="noreferrer">CI</a>,或者<a href="http://alcor.org/volunteer/" target="_blank" rel="noreferrer">志愿</a>去 Alcor 帮忙。Alcor 在<a href="http://www.alcor.org/problems.html" target="_blank" rel="noreferrer">这个页面</a>的底部列出了一些他们特别需要哪类人来帮忙。 <a class="header-anchor" href="#如果你想帮忙或参与进来——-你可以捐款给-alcor-或-ci-或者志愿去-alcor-帮忙。alcor-在这个页面的底部列出了一些他们特别需要哪类人来帮忙。" aria-label="Permalink to &quot;**如果你想帮忙或参与进来——**你可以捐款给 [Alcor](http://www.alcor.org/donate/donate.html) 或 [CI](http://www.cryonics.org/donate/),或者[志愿](http://alcor.org/volunteer/)去 Alcor 帮忙。Alcor 在[这个页面](http://www.alcor.org/problems.html)的底部列出了一些他们特别需要哪类人来帮忙。&quot;">​</a></h2><h2 id="" tabindex="-1"><a href="https://gum.co/cryonics" target="_blank" rel="noreferrer"><img src="`+d+`" alt="get the pdf"></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![get the pdf](/images/cryonics/PDF-button.png)](https://gum.co/cryonics)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,我们会在新文章发布时发给你。</p><h2 id="要支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">要支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#要支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;要支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>如果你喜欢这篇文章,你会想读这些:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/12/what-makes-you-you.html" target="_blank" rel="noreferrer">是什么让你成为你?</a></strong> —— 一篇用烧脑思想实验深挖人体冷冻最诡异、最难那个问题的文章</p><p><strong><a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">AI 革命:通往超级智能之路</a></strong> —— 某种可能比人体冷冻<em>要好得多</em>、能帮我们战胜死亡的东西(或者反过来,把我们灭绝掉)</p><p><strong><a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html" target="_blank" rel="noreferrer">SpaceX 将如何(以及为什么)殖民火星</a></strong> —— 有点像人体冷冻,只不过它想延续的不是一个人的寿命,而是<em>物种</em>的寿命</p><p>或者,来点没那么沉重的,<strong><a href="https://waitbutwhy.com/2015/03/7-3-billion-people-one-building.html" target="_blank" rel="noreferrer">这个让我对人体冷冻导致人口爆炸这件事没那么害怕了</a></strong>。</p><p><strong>资料来源</strong></p><p><a href="http://www.alcor.org" target="_blank" rel="noreferrer">Alcor 的网站</a>是个绝佳资源,尤其是他们的<a href="http://www.alcor.org/FAQs/" target="_blank" rel="noreferrer">主 FAQ</a>、<a href="http://www.alcor.org/sciencefaq.htm" target="_blank" rel="noreferrer">科学 FAQ</a> 和<a href="http://www.alcor.org/Library/index.html" target="_blank" rel="noreferrer">图书馆</a>。他们还有一个内容相当多的 <a href="https://www.youtube.com/channel/UCUh9FLcWu8k5k5W_ofWQMZA/videos?sort=p&amp;view=0&amp;flow=grid" target="_blank" rel="noreferrer">YouTube 页面</a>。飞机坠落 / 实验性降落伞那个比喻的灵感,是我从 Alcor 会员 <a href="https://www.youtube.com/watch?v=kaZjBmmhK4Y" target="_blank" rel="noreferrer">Andrew Popper</a> 的视频证词里得到的 —— 谢谢 Andrew。</p><p>这篇文章里另一个受工作之外启发的东西,是把死亡当作大魔王来写的概念,它松散地基于 Nick Bostrom 的《<a href="http://www.nickbostrom.com/fable/dragon.html" target="_blank" rel="noreferrer">龙暴君寓言</a> (The Fable of the Dragon-Tyrant)》的故事情节——在那个寓言里,死亡的角色由一条龙扮演。如果你喜欢文章里那一部分,一定要去读这个寓言。</p><p><a href="http://www.cryonics.org" target="_blank" rel="noreferrer">人体冷冻研究所</a> (Cryonics Institute) 也有很多不错的资料,尤其是他们前任主席 Ben Best 写的 <a href="http://www.benbest.com/cryonics/CryoFAQ.html" target="_blank" rel="noreferrer">FAQ</a>。</p><p>这篇文章里只聚焦 Alcor 和 CI,忽略了莫斯科郊外那家规模更小但充满热情的 <a href="http://www.kriorus.ru/en" target="_blank" rel="noreferrer">KrioRus</a>,让我觉得挺过意不去的。这里有一篇 FT Magazine 的<a href="https://www.ft.com/intl/cms/s/2/d634e198-a435-11e5-873f-68411a84f346.html#axzz42ibEhPzp" target="_blank" rel="noreferrer">好文章</a>(作者 Courtney Weaver)专门写他们。</p><p>这里有一堆和人体冷冻相关的<a href="http://www.ncbi.nlm.nih.gov/pubmed?orig_db=PubMed&amp;cmd=Search&amp;defaultField=Title%20Word&amp;term=cryonics" target="_blank" rel="noreferrer">期刊文章</a>。这里<a href="http://www.alcor.org/sciencerefs.html" target="_blank" rel="noreferrer">还有一堆</a>。</p><p>这里有一些<a href="http://www.alcor.org/Library/index.html#casereports" target="_blank" rel="noreferrer">冷冻保存案例报告</a>。</p><p>科学家兼人体冷冻主义者 Ralph Merkle 在<a href="http://www.merkle.com/cryo/" target="_blank" rel="noreferrer">他的网站</a>上很好地阐述了我聊过的不少内容。很多人把冷冻的「为什么不呢?」论证跟<a href="https://en.wikipedia.org/wiki/Pascal%27s_Wager" target="_blank" rel="noreferrer">帕斯卡赌注</a> (Pascal&#39;s Wager) 相提并论。Merkle 觉得这类比不太成立——<a href="http://www.merkle.com/cryo/wager.html" target="_blank" rel="noreferrer">这是他的理由</a>。</p><p>这是一期相当扣人心弦的 <a href="http://www.thisamericanlife.org/radio-archives/episode/354/mistakes-were-made" target="_blank" rel="noreferrer">This American Life</a> 节目,讲人体冷冻。它聚焦于 60、70 年代这场运动的早期岁月,重点讲了一起<a href="http://www.alcor.org/Library/html/suspensionfailures.html" target="_blank" rel="noreferrer">臭名昭著的冷冻灾难</a>。还有一期 <a href="http://www.stuffyoushouldknow.com/podcasts/cryonics-hi-frozen-body/" target="_blank" rel="noreferrer">Stuff You Should Know</a> 也是讲人体冷冻的。</p><p>一封由 60 位科学家联署的<a href="http://www.evidencebasedcryonics.org/scientists-open-letter-on-cryonics/" target="_blank" rel="noreferrer">公开信</a>,主张科学界应该认真对待人体冷冻。</p><p>Eliezer Yudkowsky 总有办法在我做研究的时候,把脑袋伸进大约三分之一我写的文章里。他关于人体冷冻有一堆有趣的说法。这是<a href="http://lesswrong.com/lw/wq/you_only_live_twice/" target="_blank" rel="noreferrer">其中一篇</a>。这是<a href="http://lesswrong.com/lw/1mc/normal_cryonics/" target="_blank" rel="noreferrer">另一篇</a>。</p><p>最近有两篇关于人体冷冻 (cryonics) 的好文章:一篇来自 Motherboard(作者 Brian Merchant),讲的是<a href="http://motherboard.vice.com/read/the-girl-who-would-live-forever" target="_blank" rel="noreferrer">一个即将离世的两岁女孩</a>,她的父母让她成为了世界上最年轻的人体冷冻患者。另一篇来自纽约时报(作者 Amy Harmon),我在文末引用过,讲的是一个<a href="http://www.nytimes.com/2015/09/13/us/cancer-immortality-cryogenics.html?hp&amp;action=click&amp;pgtype=Homepage&amp;module=photo-spot-region&amp;region=top-news&amp;WT.nav=top-news&amp;_r=0" target="_blank" rel="noreferrer">23 岁的女孩</a>,她在死于脑瘤前和 Alcor 签了约。</p><p>一个很有意思的 <a href="https://www.reddit.com/r/IAmA/comments/knfcx/i_am_signed_up_for_cryonics_at_my_death_ama/" target="_blank" rel="noreferrer">Reddit AMA</a>,提问对象是一位人体冷冻会员。</p><p>一篇《新闻周刊》的文章(作者 Anthony Cuthbertson),讲的是 2016 年 2 月的<a href="http://www.newsweek.com/rabbit-brain-first-mammal-brain-return-successfully-cryopreservation-424913" target="_blank" rel="noreferrer">兔脑玻璃化突破</a>。</p><p>这本我只读了节选,但这里是 Robert Ettinger 那本<a href="http://www.cryonics.org/images/uploads/misc/Prospect_Book.pdf" target="_blank" rel="noreferrer">著名的书</a>,60 年代初就是它掀起了人体冷冻运动。</p><p>一篇很有意思的《纽约》杂志文章(作者 Kerry Howley),探讨了<a href="http://www.nytimes.com/2010/07/11/magazine/11cryonics-t.html" target="_blank" rel="noreferrer">家庭因人体冷冻而起冲突</a>的现象。</p><p>一篇《大西洋》月刊的文章(作者 Rose Eveleth),讲<a href="http://www.theatlantic.com/technology/archive/2014/08/for-200000-this-lab-will-swap-your-bodys-blood-for-antifreeze/379074/" target="_blank" rel="noreferrer">人体冷冻的流程</a>。Alcor 也有<a href="http://www.alcor.org/procedures.html" target="_blank" rel="noreferrer">一个不错的页面</a>介绍这个流程。<a href="http://www.cryonics.org/ci-landing/guide-to-cryonics-procedures" target="_blank" rel="noreferrer">CI 也有一个</a>。</p><p>来认识一下 Michael Hendricks 这位聪明的科学家,<a href="https://www.technologyreview.com/s/541311/the-false-science-of-cryonics/" target="_blank" rel="noreferrer">他觉得人体冷冻就是扯淡</a>。<a href="https://www.sciencebasedmedicine.org/cold-reality-versus-the-wishful-thinking-of-cryonics/" target="_blank" rel="noreferrer">这里还有一位怀疑派</a>。<a href="http://www.smithsonianmag.com/innovation/quest-upload-mind-into-digital-space-180954946/?no-ist" target="_blank" rel="noreferrer">还有一位</a>。Alcor 用<a href="http://www.alcor.org/cryomyths.html" target="_blank" rel="noreferrer">这个页面</a>和<a href="http://www.alcor.org/notablequotes.html" target="_blank" rel="noreferrer">这个页面</a>来反驳怀疑派,并在<a href="http://www.alcor.org/problems.html" target="_blank" rel="noreferrer">这里</a>承认了人体冷冻存在的问题。</p><p>Alcor 的<a href="http://www.alcor.org/BecomeMember/scheduleA.html" target="_blank" rel="noreferrer">价格</a>。以及 <a href="http://www.cryonics.org/membership/" target="_blank" rel="noreferrer">CI 的</a>。</p><p>一段视频,Alcor 的 CEO Max More <a href="https://www.youtube.com/watch?v=JwNNdG4MZvc" target="_blank" rel="noreferrer">非常清晰地阐述了支持人体冷冻的理由</a>。</p><hr><ol><li><p>说一下注释的规则。蓝色圆圈标的是好玩/有意思的那种,你应该点开看。里面是一些额外的信息或想法,我没放进正文,要么因为只是些跑题的想法,要么因为想说的东西比正文正常水平怪一档,不太适合直接摆在那儿。<a href="#note-1-4836">↩</a></p></li><li><p>我<a href="https://www.ncbi.nlm.nih.gov/pubmed/17174021?dopt=Abstract" target="_blank" rel="noreferrer">看到</a>一个挺有意思的数据:研究显示,在医院外需要心肺复苏 (CPR) 的患者最终只有约 5% 存活,在院内需要 CPR 的患者存活率约为 15%。也就是说实际上,一份「不施行心肺复苏 (DNR)」的意愿书,大概率不会显著改变大多数人的命运。<a href="#note-2-4836">↩</a></p></li><li><p>科学家兼人体冷冻爱好者拉尔夫·默克尔 (Ralph Merkle) <a href="http://www.merkle.com/cryo/probability.html" target="_blank" rel="noreferrer">讨论过</a>像阿尔茨海默这类疾病对一个人冷冻前景可能造成的损害范围:「如果轻度痴呆只是损伤了负责调取记忆痕迹的神经机制,而记忆痕迹本身相对完好,那么运用未来足够先进的技术是完全可以逆转的。但如果重度痴呆已经摧毁了记忆痕迹本身,任何未来技术都无能为力。而目前,在大多数情况下,我们无法可靠地区分这两种情况。」<a href="#note-3-4836">↩</a></p></li><li><p>再<em>下一步</em>会难得多——操纵原子核里的亚原子粒子,比如质子和中子。那些东西<em>小得多</em>——一个质子的直径大约 1.7 飞米,而 1 飞米是<em>1 纳米</em>的百万分之一。<a href="#note-4-4836">↩</a></p></li><li><p>能操纵单个质子的技术,就好比一个大得多的巨人,身高从太阳一直伸到土星,在地球上摆弄 1 毫米大小的沙粒。对那个巨人来说,<em>整个地球</em>只有 1/50 毫米——得用显微镜才能看到——而他还得精准地移动地球上单粒的<em>沙子</em>。这就能看出质子有多小了。<a href="#note-5-4836">↩</a></p></li><li><p>想更详细地了解这个概念,可以看<a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">我那篇 AI 文章</a>的开头部分。<a href="#note-6-4836">↩</a></p></li><li><p>Alcor 针对 Storey 说法的<a href="http://www.alcor.org/notablequotes.html" target="_blank" rel="noreferrer">完整回应</a>:「这段惊人陈述里的每一条声明都是错的。正如<a href="http://www.alcor.org/Library/html/hippocampus.html" target="_blank" rel="noreferrer">上面的示意图</a>所示,在高浓度冷冻保护剂存在的情况下,脑组织的结构保存是非常好的。而且,我们现在关于阿尔茨海默和其他脑部疾病的大量知识,都是通过对神经研究脑库中冷冻脑组织的组织化学分析得来的——而那些脑库根本没用任何冷冻保护剂。如果生物分子无法通过冷冻保存——哪怕是临床死亡数小时之后——这些脑库根本不会存在。当受人尊敬的低温生物学家在全国性舞台上散布如此严重错误的信息时,难怪人体冷冻要争取科学认可如此艰难。」<a href="#note-7-4836">↩</a></p></li><li><p>比如 Alcor 在他们网站上就承认「缺乏明确的结果,依然是人体冷冻最大的弱点之一,因为这会助长自满、也让问责变得不可能。」<a href="#note-8-4836">↩</a></p></li><li><p>Alcor 的<a href="http://www.alcor.org/FAQs/faq01.html" target="_blank" rel="noreferrer">常见问题页面</a>里的这句话,就是我说的那种典型:「以目前的科学知识,我们无法可靠地知道某种程度的保存状况,在经过大规模修复后会对应多少程度的记忆保留。但未来使用先进技术的复杂恢复手段,也许能让记忆在如今许多人认为几乎毫无希望的损伤程度下,依然可以恢复。」<a href="#note-9-4836">↩</a></p></li><li><p>这个「死亡作为霸主」的类比,大致基于尼克·博斯特罗姆 (Nick Bostrom) 那篇超棒的小故事 <em><a href="http://www.nickbostrom.com/fable/dragon.html" target="_blank" rel="noreferrer">The Fable of the Dragon-Tyrant (龙暴君寓言)</a></em> 的情节,里面死亡的角色是由一条龙扮演的。<a href="#note-10-4836">↩</a></p></li><li><p>在我做资料研究时,看到<a href="http://www.nytimes.com/2010/07/11/magazine/11cryonics-t.html" target="_blank" rel="noreferrer">大量故事</a>都涉及围绕人体冷冻的家庭冲突。往往是夫妻中的一方(通常是丈夫)计划签约,而配偶讨厌这个想法,有时会觉得自己被抛下了。我个人觉得这种反应挺自私的,但我也理解——如果你不打算签,而伴侣却坚持要签,那确实可能挺伤人的。</p></li></ol><pre><code>有时这类分歧会闹得非常难看,以至于冷冻当事人不得不把授权委托权交给家庭以外的人,因为他们不相信家人会尊重自己的意愿。金·苏奥兹 (Kim Suozzi) 的案例里,她就把授权委托权给了她的男友,因为她父亲坚决反对冷冻计划。[↩](#note-11-4836)
</code></pre><hr><ol><li><p>灰色方块是无聊的东西,你点开一个灰色方块,最后只会觉得无聊。这些只是来源和引用。<a href="#note2-1-4836">↩</a></p></li><li><p>The Atlantic: <a href="http://www.theatlantic.com/technology/archive/2014/08/for-200000-this-lab-will-swap-your-bodys-blood-for-antifreeze/379074/" target="_blank" rel="noreferrer">For $200,000, This Lab Will Swap Your Body&#39;s Blood for Antifreeze</a><a href="#note2-2-4836">↩</a></p></li><li><p>Alcor: <a href="http://www.alcor.org/sciencefaq.htm" target="_blank" rel="noreferrer">Science FAQ</a><a href="#note2-3-4836">↩</a></p></li><li><p>BBC: Cryopreservation: &#39;I Freeze People to Cheat Death&quot;<a href="#note2-4-4836">↩</a></p></li><li><p>ULC: <a href="http://www.uniformlaws.org/ActSummary.aspx?title=Determination%20of%20Death%20Act" target="_blank" rel="noreferrer">Determination of Death Act Summary</a><a href="#note2-5-4836">↩</a></p></li><li><p><a href="http://future.wikia.com/wiki/Alcor_Life_Extension_Foundation" target="_blank" rel="noreferrer">http://future.wikia.com/wiki/Alcor_Life_Extension_Foundation</a><a href="#note2-6-4836">↩</a></p></li><li><p>图片:<a href="http://www.michiganinstruments.com/trade-in-program" target="_blank" rel="noreferrer">Michigan Instruments</a><a href="#note2-7-4836">↩</a></p></li><li><p>图片:<a href="http://www.alcor.org/Library/pdfs/atp.pdf" target="_blank" rel="noreferrer">Alcor</a><a href="#note2-8-4836">↩</a></p></li><li><p>图片:<a href="http://www.alcor.org/cryomyths.html" target="_blank" rel="noreferrer">Alcor</a><a href="#note2-9-4836">↩</a></p></li><li><p>RT. <a href="https://www.rt.com/news/332074-cryonics-rabbit-brain-regenerated/" target="_blank" rel="noreferrer">Frozen rabbit brain brought back in &#39;near perfect&#39; condition in cryonics breakthrough</a><a href="#note2-10-4836">↩</a></p></li><li><p>图片:<a href="http://www.alcor.org/AtWork/index.html" target="_blank" rel="noreferrer">Alcor</a><a href="#note2-11-4836">↩</a></p></li><li><p>图片:<a href="http://www.alcor.org/AtWork/index.html" target="_blank" rel="noreferrer">Alcor</a><a href="#note2-12-4836">↩</a></p></li><li><p>Mark Mayford, Steven A. Siegelbaum, and Eric R. Kandel: <a href="http://cshperspectives.cshlp.org/content/4/6/a005751.full.pdf" target="_blank" rel="noreferrer">Synapses and Memory Storage</a>.<a href="#note2-13-4836">↩</a></p></li><li><p>Less Wrong: <a href="http://lesswrong.com/lw/wq/you_only_live_twice/" target="_blank" rel="noreferrer">You Only Live Twice</a><a href="#note2-14-4836">↩</a></p></li><li><p>Motherboard: <a href="http://motherboard.vice.com/read/the-girl-who-would-live-forever" target="_blank" rel="noreferrer">The Girl Who Would Live Forever</a><a href="#note2-15-4836">↩</a></p></li><li><p><a href="http://www.alcor.org/FAQs/faq01.html" target="_blank" rel="noreferrer">Alcor FAQ</a><a href="#note2-16-4836">↩</a></p></li><li><p><a href="http://www.alcor.org/FAQs/faq07.html" target="_blank" rel="noreferrer">Alcor FAQ</a><a href="#note2-17-4836">↩</a></p></li><li><p>图片:<a href="https://www.pinterest.com/katherine1814/cumple-5-care-bears/" target="_blank" rel="noreferrer">Pinterest</a><a href="#note2-18-4836">↩</a></p></li><li><p>&quot;Frozen in Time,&quot; Miami Herald, Sept. 17, 2002.<a href="#note2-19-4836">↩</a></p></li><li><p>Alcor: <a href="http://www.alcor.org/notablequotes.html" target="_blank" rel="noreferrer">Notable Quotes</a><a href="#note2-20-4836">↩</a></p></li><li><p><a href="http://people.ucalgary.ca/~kmuldrew/cryo_course/course_outline.html" target="_blank" rel="noreferrer">University of Calgary</a><a href="#note2-21-4836">↩</a></p></li><li><p>Alcor: <a href="http://www.alcor.org/notablequotes.html" target="_blank" rel="noreferrer">Notable Quotes</a><a href="#note2-22-4836">↩</a></p></li><li><p><a href="http://www.alcor.org/FAQs/faq07.html" target="_blank" rel="noreferrer">Alcor FAQ</a><a href="#note2-23-4836">↩</a></p></li><li><p><a href="http://www.ocregister.com/articles/frozen-330223-king-cryonics.html" target="_blank" rel="noreferrer">http://www.ocregister.com/articles/frozen-330223-king-cryonics.html</a><a href="#note2-24-4836">↩</a></p></li><li><p><a href="http://www.merkle.com/cryo/" target="_blank" rel="noreferrer">Merkle.com</a><a href="#note2-25-4836">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2016/03/cryonics.html&amp;description=Why%20Cryonics%20Makes%20Sense" target="_blank" rel="noreferrer"><img src="`+A+'" alt=""></a></p>',347)])])}const I=e(q,[["render",C]]);export{F as __pageData,I as default};
